    {"offset": {"line": 728, "column": 0}, "map": {"version":3,"sources":["file:///C:/Users/LWRSH/Documents/Loveworld-Singers-Rehearsal-Hub-Portal-Zonal-Mode/src/lib/firebase-setup.ts"],"sourcesContent":["import { initializeApp, getApp, FirebaseApp } from 'firebase/app'\r\nimport { getAuth, setPersistence, browserLocalPersistence } from 'firebase/auth'\r\nimport { initializeFirestore, getFirestore, Firestore } from 'firebase/firestore'\r\nimport { getStorage } from 'firebase/storage'\r\nimport { getDatabase, Database } from 'firebase/database'\r\n\r\nconst firebaseConfig = {\r\n  apiKey: process.env.NEXT_PUBLIC_FIREBASE_API_KEY || '',\r\n  authDomain: process.env.NEXT_PUBLIC_FIREBASE_AUTH_DOMAIN || '',\r\n  databaseURL: process.env.NEXT_PUBLIC_FIREBASE_DATABASE_URL || '',\r\n  projectId: process.env.NEXT_PUBLIC_FIREBASE_PROJECT_ID || '',\r\n  storageBucket: process.env.NEXT_PUBLIC_FIREBASE_STORAGE_BUCKET || '',\r\n  messagingSenderId: process.env.NEXT_PUBLIC_FIREBASE_MESSAGING_SENDER_ID || '',\r\n  appId: process.env.NEXT_PUBLIC_FIREBASE_APP_ID || '',\r\n  measurementId: process.env.NEXT_PUBLIC_FIREBASE_MEASUREMENT_ID || ''\r\n}\r\n\r\nif (!firebaseConfig.apiKey || !firebaseConfig.projectId) {\r\n  throw new Error('Firebase configuration missing. Check .env.local file.')\r\n}\r\n\r\nlet app: FirebaseApp\r\ntry {\r\n  app = initializeApp(firebaseConfig)\r\n} catch (error: any) {\r\n  if (error.code === 'app/duplicate-app') {\r\n    app = getApp()\r\n  } else {\r\n    throw error\r\n  }\r\n}\r\n\r\nexport const auth = getAuth(app)\r\n\r\nexport const db: Firestore = (() => {\r\n  try {\r\n    return initializeFirestore(app, {\r\n      experimentalForceLongPolling: false,\r\n      experimentalAutoDetectLongPolling: true,\r\n      localCache: { kind: 'persistent' }\r\n    })\r\n  } catch (error: any) {\r\n    if (error.code === 'firestore/already-exists') {\r\n      return getFirestore(app)\r\n    }\r\n    throw error\r\n  }\r\n})()\r\n\r\nexport const storage = getStorage(app)\r\n\r\nlet _realtimeDb: Database | null = null;\r\n\r\nexport const realtimeDb: Database | null = (() => {\r\n  if (typeof window !== 'undefined') { // Only initialize on client side\r\n    try {\r\n      if (!_realtimeDb) {\r\n        _realtimeDb = getDatabase(app);\r\n      }\r\n      return _realtimeDb;\r\n    } catch (error) {\r\n      console.warn('Failed to initialize Realtime Database:', error);\r\n      return null;\r\n    }\r\n  } else {\r\n    // Return null on server-side to prevent build failures\r\n    return null;\r\n  }\r\n})()\r\n\r\nexport function isRealtimeDbAvailable(): boolean {\r\n  return realtimeDb !== null;\r\n}\r\n\r\nif (typeof window !== 'undefined') {\r\n  setPersistence(auth, browserLocalPersistence).catch(console.error)\r\n}\r\n\r\nexport default app\r\n"],"names":[],"mappings":";;;;;;;;;;;;;;AAAA;AAAA;AACA;AAAA;AACA;AAAA;AACA;AAAA;AACA;;;;;;AAEA,MAAM,iBAAiB;IACrB,QAAQ,+EAA4C;IACpD,YAAY,6EAAgD;IAC5D,aAAa,iGAAiD;IAC9D,WAAW,6DAA+C;IAC1D,eAAe,iFAAmD;IAClE,mBAAmB,oDAAwD;IAC3E,OAAO,iFAA2C;IAClD,eAAe,oDAAmD;AACpE;AAEA,IAAI,CAAC,eAAe,MAAM,IAAI,CAAC,eAAe,SAAS,EAAE;IACvD,MAAM,IAAI,MAAM;AAClB;AAEA,IAAI;AACJ,IAAI;IACF,MAAM,IAAA,iLAAa,EAAC;AACtB,EAAE,OAAO,OAAY;IACnB,IAAI,MAAM,IAAI,KAAK,qBAAqB;QACtC,MAAM,IAAA,0KAAM;IACd,OAAO;QACL,MAAM;IACR;AACF;AAEO,MAAM,OAAO,IAAA,6KAAO,EAAC;AAErB,MAAM,KAAgB,CAAC;IAC5B,IAAI;QACF,OAAO,IAAA,oNAAmB,EAAC,KAAK;YAC9B,8BAA8B;YAC9B,mCAAmC;YACnC,YAAY;gBAAE,MAAM;YAAa;QACnC;IACF,EAAE,OAAO,OAAY;QACnB,IAAI,MAAM,IAAI,KAAK,4BAA4B;YAC7C,OAAO,IAAA,6MAAY,EAAC;QACtB;QACA,MAAM;IACR;AACF,CAAC;AAEM,MAAM,UAAU,IAAA,kMAAU,EAAC;AAElC,IAAI,cAA+B;AAE5B,MAAM,aAA8B,CAAC;IAC1C;;SAUO;QACL,uDAAuD;QACvD,OAAO;IACT;AACF,CAAC;AAEM,SAAS;IACd,OAAO,eAAe;AACxB;AAEA;;uCAIe","debugId":null}},
    {"offset": {"line": 816, "column": 0}, "map": {"version":3,"sources":["file:///C:/Users/LWRSH/Documents/Loveworld-Singers-Rehearsal-Hub-Portal-Zonal-Mode/src/lib/session-manager.ts"],"sourcesContent":["// Session Management Service - Concurrent Login Prevention\r\nimport { doc, setDoc, getDoc, onSnapshot, deleteDoc, serverTimestamp } from 'firebase/firestore'\r\nimport { db } from './firebase-setup'\r\nimport { User } from 'firebase/auth'\r\n\r\ninterface UserSession {\r\n  userId: string\r\n  deviceId: string\r\n  deviceInfo: string\r\n  deviceModel: string\r\n  browserInfo: string\r\n  osInfo: string\r\n  loginTime: any\r\n  lastActivity: any\r\n  isActive: boolean\r\n  terminatedAt?: any\r\n  terminatedByDeviceId?: string\r\n  terminatedReason?: string\r\n}\r\n\r\nexport class SessionManager {\r\n  private static deviceId: string = ''\r\n  private static sessionListener: (() => void) | null = null\r\n  \r\n  // Generate unique device ID\r\n  static generateDeviceId(): string {\r\n    if (this.deviceId) return this.deviceId\r\n    \r\n    // Create unique device fingerprint\r\n    const canvas = document.createElement('canvas')\r\n    const ctx = canvas.getContext('2d')\r\n    ctx!.textBaseline = 'top'\r\n    ctx!.font = '14px Arial'\r\n    ctx!.fillText('Device fingerprint', 2, 2)\r\n    \r\n    const fingerprint = canvas.toDataURL()\r\n    const userAgent = navigator.userAgent\r\n    const screen = `${window.screen.width}x${window.screen.height}`\r\n    const timezone = Intl.DateTimeFormat().resolvedOptions().timeZone\r\n    \r\n    this.deviceId = btoa(`${fingerprint}-${userAgent}-${screen}-${timezone}`).slice(0, 32)\r\n    return this.deviceId\r\n  }\r\n  \r\n  // Get device info for display\r\n  static getDeviceInfo(): string {\r\n    const userAgent = navigator.userAgent\r\n    let deviceInfo = 'Unknown Device'\r\n    \r\n    if (/iPhone|iPad|iPod/.test(userAgent)) {\r\n      deviceInfo = 'iPhone/iPad'\r\n    } else if (/Android/.test(userAgent)) {\r\n      deviceInfo = 'Android Device'\r\n    } else if (/Windows/.test(userAgent)) {\r\n      deviceInfo = 'Windows PC'\r\n    } else if (/Mac/.test(userAgent)) {\r\n      deviceInfo = 'Mac'\r\n    } else if (/Linux/.test(userAgent)) {\r\n      deviceInfo = 'Linux PC'\r\n    }\r\n    \r\n    // Add browser info\r\n    if (/Chrome/.test(userAgent)) deviceInfo += ' (Chrome)'\r\n    else if (/Firefox/.test(userAgent)) deviceInfo += ' (Firefox)'\r\n    else if (/Safari/.test(userAgent)) deviceInfo += ' (Safari)'\r\n    else if (/Edge/.test(userAgent)) deviceInfo += ' (Edge)'\r\n    \r\n    // Add specific device model if available\r\n    const deviceModel = this.getDeviceModel(userAgent)\r\n    if (deviceModel) {\r\n      deviceInfo = deviceModel + ' ' + deviceInfo\r\n    }\r\n    \r\n    return deviceInfo\r\n  }\r\n  \r\n  // Get specific device model\r\n  static getDeviceModel(userAgent: string): string | null {\r\n    // Samsung devices\r\n    const samsungMatch = userAgent.match(/SM-[A-Z0-9]+/)\r\n    if (samsungMatch) {\r\n      return `Samsung ${samsungMatch[0]}`\r\n    }\r\n    \r\n    // Itel devices\r\n    const itelMatch = userAgent.match(/itel[ _][A-Z0-9]+/i)\r\n    if (itelMatch) {\r\n      return itelMatch[0].replace(/_/g, ' ')\r\n    }\r\n    \r\n    // Other Android devices\r\n    const androidMatch = userAgent.match(/Android.*?([A-Za-z0-9 ]+?)(?:Build|;)/)\r\n    if (androidMatch) {\r\n      return androidMatch[1].trim()\r\n    }\r\n    \r\n    return null\r\n  }\r\n  \r\n  // Get browser information\r\n  static getBrowserInfo(): string {\r\n    const userAgent = navigator.userAgent\r\n    if (/Chrome/.test(userAgent)) return 'Chrome'\r\n    if (/Firefox/.test(userAgent)) return 'Firefox'\r\n    if (/Safari/.test(userAgent)) return 'Safari'\r\n    if (/Edge/.test(userAgent)) return 'Edge'\r\n    return 'Unknown Browser'\r\n  }\r\n  \r\n  // Get OS information\r\n  static getOSInfo(): string {\r\n    const userAgent = navigator.userAgent\r\n    if (/Windows/.test(userAgent)) return 'Windows'\r\n    if (/Mac/.test(userAgent)) return 'macOS'\r\n    if (/Linux/.test(userAgent)) return 'Linux'\r\n    if (/Android/.test(userAgent)) return 'Android'\r\n    if (/iPhone|iPad|iPod/.test(userAgent)) return 'iOS'\r\n    return 'Unknown OS'\r\n  }\r\n  \r\n  // Check if user can login (Single-device policy - block new login if another device active)\r\n  static async canUserLogin(userId: string): Promise<{ canLogin: boolean; activeDevice?: string }> {\r\n    try {\r\n      const currentDeviceId = this.generateDeviceId()\r\n      const sessionRef = doc(db, 'user_sessions', userId)\r\n      const sessionDoc = await getDoc(sessionRef)\r\n\r\n      if (!sessionDoc.exists()) {\r\n        return { canLogin: true }\r\n      }\r\n\r\n      const session = sessionDoc.data() as UserSession\r\n      if (session.isActive && session.deviceId && session.deviceId !== currentDeviceId) {\r\n        return { canLogin: false, activeDevice: session.deviceInfo || 'another device' }\r\n      }\r\n\r\n      return { canLogin: true }\r\n    } catch (_e) {\r\n    return { canLogin: true }\r\n    }\r\n  }\r\n  \r\n  // Create new session for user (terminates existing sessions)\r\n  static async createSession(user: User): Promise<void> {\r\n    try {\r\n      const deviceId = this.generateDeviceId()\r\n      const deviceInfo = this.getDeviceInfo()\r\n      const deviceModel = this.getDeviceModel(navigator.userAgent) || 'Unknown'\r\n      const browserInfo = this.getBrowserInfo()\r\n      const osInfo = this.getOSInfo()\r\n      \r\n      // Terminate any existing session for this user\r\n      await this.terminateExistingSession(user.uid, deviceId)\r\n      \r\n      const session: UserSession = {\r\n        userId: user.uid,\r\n        deviceId,\r\n        deviceInfo,\r\n        deviceModel,\r\n        browserInfo,\r\n        osInfo,\r\n        loginTime: serverTimestamp(),\r\n        lastActivity: serverTimestamp(),\r\n        isActive: true\r\n      }\r\n      \r\n      const sessionRef = doc(db, 'user_sessions', user.uid)\r\n      await setDoc(sessionRef, session)\r\n      \r\n      // Start activity tracking\r\n      this.startActivityTracking(user.uid)\r\n      \r\n      console.log('✅ Session created for device:', deviceInfo)\r\n    } catch (error) {\r\n      console.error('Error creating session:', error)\r\n    }\r\n  }\r\n  \r\n  // Terminate existing session for user (Facebook-style)\r\n  static async terminateExistingSession(userId: string, currentDeviceId: string): Promise<void> {\r\n    try {\r\n      const sessionRef = doc(db, 'user_sessions', userId)\r\n      const sessionDoc = await getDoc(sessionRef)\r\n      \r\n      if (sessionDoc.exists()) {\r\n        const session = sessionDoc.data() as UserSession\r\n        \r\n        // If existing session is on a different device, notify it\r\n        if (session.deviceId !== currentDeviceId) {\r\n          // Update the session to mark it as terminated\r\n          await setDoc(sessionRef, {\r\n            ...session,\r\n            isActive: false,\r\n            terminatedAt: serverTimestamp(),\r\n            terminatedByDeviceId: currentDeviceId\r\n          }, { merge: true })\r\n        }\r\n      }\r\n    } catch (error) {\r\n      console.error('Error terminating existing session:', error)\r\n    }\r\n  }\r\n  \r\n  // Update last activity\r\n  static async updateActivity(userId: string): Promise<void> {\r\n    try {\r\n      const sessionRef = doc(db, 'user_sessions', userId)\r\n      await setDoc(sessionRef, {\r\n        lastActivity: serverTimestamp()\r\n      }, { merge: true })\r\n    } catch (error) {\r\n      console.error('Error updating activity:', error)\r\n    }\r\n  }\r\n  \r\n  // Start tracking user activity\r\n  static startActivityTracking(userId: string): void {\r\n    // DISABLED - Session tracking causes page reloads\r\n    // Just log the activity without forcing logouts\r\n    console.log('📊 Activity tracking disabled to prevent reloads')\r\n  }\r\n  \r\n  // Handle session termination (user logged in elsewhere)\r\n  static handleSessionTermination(): void {\r\n    // DISABLED - No more forced reloads\r\n    // Just clear the session silently, let React handle the UI\r\n    console.log('⚠️ Session terminated on another device')\r\n  }\r\n  \r\n  // End session\r\n  static async endSession(userId: string): Promise<void> {\r\n    try {\r\n      const sessionRef = doc(db, 'user_sessions', userId)\r\n      await deleteDoc(sessionRef)\r\n      \r\n      if (this.sessionListener) {\r\n        this.sessionListener()\r\n        this.sessionListener = null\r\n      }\r\n      \r\n      console.log('✅ Session ended')\r\n    } catch (error) {\r\n      console.error('Error ending session:', error)\r\n    }\r\n  }\r\n  \r\n  // Force logout user from all devices (admin function)\r\n  static async forceLogoutUser(userId: string): Promise<void> {\r\n    try {\r\n      const sessionRef = doc(db, 'user_sessions', userId)\r\n      await setDoc(sessionRef, {\r\n        isActive: false,\r\n        terminatedAt: serverTimestamp(),\r\n        terminatedReason: 'admin_force_logout'\r\n      }, { merge: true })\r\n      console.log('✅ User force logged out from all devices')\r\n    } catch (error) {\r\n      console.error('Error force logging out user:', error)\r\n    }\r\n  }\r\n}"],"names":[],"mappings":"AAAA,2DAA2D;;;;;AAC3D;AAAA;AACA;;;AAkBO,MAAM;IACX,OAAe,WAAmB,GAAE;IACpC,OAAe,kBAAuC,KAAI;IAE1D,4BAA4B;IAC5B,OAAO,mBAA2B;QAChC,IAAI,IAAI,CAAC,QAAQ,EAAE,OAAO,IAAI,CAAC,QAAQ;QAEvC,mCAAmC;QACnC,MAAM,SAAS,SAAS,aAAa,CAAC;QACtC,MAAM,MAAM,OAAO,UAAU,CAAC;QAC9B,IAAK,YAAY,GAAG;QACpB,IAAK,IAAI,GAAG;QACZ,IAAK,QAAQ,CAAC,sBAAsB,GAAG;QAEvC,MAAM,cAAc,OAAO,SAAS;QACpC,MAAM,YAAY,UAAU,SAAS;QACrC,MAAM,SAAS,GAAG,OAAO,MAAM,CAAC,KAAK,CAAC,CAAC,EAAE,OAAO,MAAM,CAAC,MAAM,EAAE;QAC/D,MAAM,WAAW,KAAK,cAAc,GAAG,eAAe,GAAG,QAAQ;QAEjE,IAAI,CAAC,QAAQ,GAAG,KAAK,GAAG,YAAY,CAAC,EAAE,UAAU,CAAC,EAAE,OAAO,CAAC,EAAE,UAAU,EAAE,KAAK,CAAC,GAAG;QACnF,OAAO,IA