K;QACvB,EAAE,OAAO,OAAY;YACnB,OAAO;gBAAE,OAAO,MAAM,OAAO;YAAC;QAChC;IACF;IAEA,aAAa,wBAAwB,OAAe,EAAE;QACpD,IAAI;YACF,MAAM,EAAE,uBAAuB,EAAE,GAAG;YACpC,MAAM,QAAQ,MAAM,wBAAwB,uIAAI,EAAE;YAClD,OAAO;gBAAE;gBAAO,OAAO;YAAK;QAC9B,EAAE,OAAO,OAAY;YACnB,OAAO;gBAAE,OAAO;gBAAM,OAAO,MAAM,OAAO;YAAC;QAC7C;IACF;IAEA,aAAa,qBAAqB,OAAe,EAAE,WAAmB,EAAE;QACtE,IAAI;YACF,MAAM,EAAE,oBAAoB,EAAE,GAAG;YACjC,MAAM,qBAAqB,uIAAI,EAAE,SAAS;YAC1C,OAAO;gBAAE,OAAO;YAAK;QACvB,EAAE,OAAO,OAAY;YACnB,OAAO;gBAAE,OAAO,MAAM,OAAO;YAAC;QAChC;IACF;IAEA,aAAa,eAAe,WAAmB,EAAE;QAC/C,IAAI;YACF,MAAM,EAAE,cAAc,EAAE,GAAG;YAC3B,MAAM,OAAO,uIAAI,CAAC,WAAW;YAC7B,IAAI,CAAC,MAAM,MAAM,IAAI,MAAM;YAC3B,MAAM,eAAe,MAAM;YAC3B,OAAO;gBAAE,OAAO;YAAK;QACvB,EAAE,OAAO,OAAY;YACnB,OAAO;gBAAE,OAAO,MAAM,OAAO;YAAC;QAChC;IACF;IAEA,aAAa,mBAAmB;QAC9B,IAAI;YACF,MAAM,IAAA,oLAAc,EAAC,uIAAI,EAAE,6LAAuB;YAClD,MAAM,WAAW,IAAI,wLAAkB;YACvC,MAAM,SAAS,MAAM,IAAA,qLAAe,EAAC,uIAAI,EAAE;YAE3C,MAAM,cAAc,MAAM,IAAI,CAAC,cAAc,CAAC,OAAO,IAAI,CAAC,GAAG;YAC7D,IAAI,CAAC,aAAa;gBAChB,MAAM,cAAc,OAAO,IAAI,CAAC,WAAW,IAAI;gBAC/C,MAAM,YAAY,YAAY,KAAK,CAAC;gBACpC,MAAM,IAAA,uMAAM,EAAC,IAAA,oMAAG,EAAC,qIAAE,EAAE,YAAY,OAAO,IAAI,CAAC,GAAG,GAAG;oBACjD,IAAI,OAAO,IAAI,CAAC,GAAG;oBACnB,YAAY,SAAS,CAAC,EAAE,IAAI;oBAC5B,WAAW,UAAU,KAAK,CAAC,GAAG,IAAI,CAAC,QAAQ;oBAC3C,OAAO,OAAO,IAAI,CAAC,KAAK;oBACxB,mBAAmB;oBACnB,YAAY,IAAI,OAAO,WAAW;oBAClC,YAAY,IAAI,OAAO,WAAW;gBACpC;YACF;YAEA,OAAO;gBAAE,MAAM,OAAO,IAAI;gBAAE,OAAO;YAAK;QAC1C,EAAE,OAAO,OAAY;YACnB,OAAO;gBAAE,MAAM;gBAAM,OAAO,MAAM,OAAO;YAAC;QAC5C;IACF;IAEA,aAAa,aAAa;QACxB,IAAI;YACF,MAAM,OAAO,uIAAI,CAAC,WAAW;YAC7B,IAAI,CAAC,MAAM,MAAM,IAAI,MAAM;YAC3B,MAAM,IAAA,gLAAU,EAAC;YACjB,OAAO;gBAAE,SAAS;gBAAM,OAAO;YAAK;QACtC,EAAE,OAAO,OAAY;YACnB,OAAO;gBAAE,SAAS;gBAAO,OAAO,MAAM,OAAO;YAAC;QAChD;IACF;AACF","debugId":null}},
    {"offset": {"line": 1544, "column": 0}, "map": {"version":3,"sources":["file:///C:/Users/LWRSH/Documents/Loveworld-Singers-Rehearsal-Hub-Portal-Zonal-Mode/src/utils/low-data-optimizer.ts"],"sourcesContent":["// Low Data Optimizer - Super fast loading with minimal Firebase costs\r\n// Instagram-style optimization for poor connections\r\n\r\ninterface ConnectionInfo {\r\n  effectiveType: string;\r\n  downlink: number;\r\n  rtt: number;\r\n  saveData: boolean;\r\n}\r\n\r\nclass LowDataOptimizer {\r\n  private static instance: LowDataOptimizer;\r\n  private connectionInfo: ConnectionInfo | null = null;\r\n  private isLowData = false;\r\n  private cache = new Map<string, { data: any; timestamp: number; ttl: number }>();\r\n  \r\n  // Cache TTLs based on connection speed\r\n  private readonly TTL = {\r\n    FAST: 5 * 60 * 1000,      // 5 minutes for fast connections\r\n    SLOW: 30 * 60 * 1000,     // 30 minutes for slow connections\r\n    VERY_SLOW: 2 * 60 * 60 * 1000, // 2 hours for very slow connections\r\n    OFFLINE: 24 * 60 * 60 * 1000   // 24 hours when offline\r\n  };\r\n\r\n  static getInstance(): LowDataOptimizer {\r\n    if (!LowDataOptimizer.instance) {\r\n      LowDataOptimizer.instance = new LowDataOptimizer();\r\n    }\r\n    return LowDataOptimizer.instance;\r\n  }\r\n\r\n  init() {\r\n    this.detectConnection();\r\n    this.setupEventListeners();\r\n    console.log('📱 Low Data Optimizer initialized');\r\n  }\r\n\r\n  private detectConnection() {\r\n    if ('connection' in navigator) {\r\n      const connection = (navigator as any).connection;\r\n      this.connectionInfo = {\r\n        effectiveType: connection.effectiveType || 'unknown',\r\n        downlink: connection.downlink || 0,\r\n        rtt: connection.rtt || 0,\r\n        saveData: connection.saveData || false\r\n      };\r\n\r\n      // Determine if this is a low data connection\r\n      this.isLowData = \r\n        this.connectionInfo.effectiveType === 'slow-2g' ||\r\n        this.connectionInfo.effectiveType === '2g' ||\r\n        this.connectionInfo.downlink < 1 ||\r\n        this.connectionInfo.saveData;\r\n\r\n      console.log('📊 Connection detected:', {\r\n        type: this.connectionInfo.effectiveType,\r\n        speed: this.connectionInfo.downlink + 'Mbps',\r\n        rtt: this.connectionInfo.rtt + 'ms',\r\n        saveData: this.connectionInfo.saveData,\r\n        isLowData: this.isLowData\r\n      });\r\n\r\n      if (this.isLowData) {\r\n        console.log('⚠️ Low data connection detected - enabling aggressive caching');\r\n      }\r\n    }\r\n  }\r\n\r\n  private setupEventListeners() {\r\n    if ('connection' in navigator) {\r\n      const connection = (navigator as any).connection;\r\n      connection.addEventListener('change', () => {\r\n        this.detectConnection();\r\n      });\r\n    }\r\n\r\n    // Listen for online/offline events\r\n    window.addEventListener('online', () => {\r\n      console.log('🌐 Connection restored');\r\n      this.detectConnection();\r\n    });\r\n\r\n    window.addEventListener('offline', () => {\r\n      console.log('📴 Connection lost');\r\n      this.isLowData = true;\r\n    });\r\n  }\r\n\r\n  // Get cache TTL based on connection speed\r\n  getCacheTTL(): number {\r\n    if (!navigator.onLine) return this.TTL.OFFLINE;\r\n    if (!this.connectionInfo) return this.TTL.FAST;\r\n    \r\n    switch (this.connectionInfo.effectiveType) {\r\n      case 'slow-2g':\r\n      case '2g':\r\n        return this.TTL.VERY_SLOW;\r\n      case '3g':\r\n        return this.TTL.SLOW;\r\n      default:\r\n        return this.TTL.FAST;\r\n    }\r\n  }\r\n\r\n  // Smart caching with connection-aware TTL\r\n  set(key: string, data: any): void {\r\n    const ttl = this.getCacheTTL();\r\n    this.cache.set(key, {\r\n      data,\r\n      timestamp: Date.now(),\r\n      ttl\r\n    });\r\n\r\n    // Also store in localStorage for persistence\r\n    try {\r\n      localStorage.setItem(`lowdata_${key}`, JSON.stringify({\r\n        data,\r\n        timestamp: Date.now(),\r\n        ttl\r\n      }));\r\n    } catch (error) {\r\n      console.warn('Failed to store in localStorage:', error);\r\n    }\r\n\r\n    console.log(`💾 Cached ${key} for ${ttl/1000/60} minutes (low data mode)`);\r\n  }\r\n\r\n  get(key: string): any | null {\r\n    // Check memory cache first\r\n    const cached = this.cache.get(key);\r\n    if (cached && Date.now() - cached.timestamp < cached.ttl) {\r\n      console.log(`⚡ Cache hit: ${key} (instant load)`);\r\n      return cached.data;\r\n    }\r\n\r\n    // Check localStorage\r\n    try {\r\n      const stored = localStorage.getItem(`lowdata_${key}`);\r\n      if (stored) {\r\n        const parsed = JSON.parse(stored);\r\n        if (Date.now() - parsed.timestamp < parsed.ttl) {\r\n          // Restore to memory cache\r\n          this.cache.set(key, parsed);\r\n          console.log(`💾 Restored ${key} from localStorage`);\r\n          return parsed.data;\r\n        } else {\r\n          // Expired, remove it\r\n          localStorage.removeItem(`lowdata_${key}`);\r\n        }\r\n      }\r\n    } catch (error) {\r\n      console.warn('Failed to read from localStorage:', error);\r\n    }\r\n\r\n    return null;\r\n  }\r\n\r\n  // Check if we should make a Firebase request\r\n  shouldFetch(key: string): boolean {\r\n    const cached = this.get(key);\r\n    if (cached) {\r\n      console.log(`🚫 Skipping Firebase request for ${key} (cached)`);\r\n      return false;\r\n    }\r\n    \r\n    console.log(`🔥 Making Firebase request for ${key}`);\r\n    return true;\r\n  }\r\n\r\n  // Get connection info\r\n  getConnectionInfo(): ConnectionInfo | null {\r\n    return this.connectionInfo;\r\n  }\r\n\r\n  // Check if low data mode\r\n  isLowDataMode(): boolean {\r\n    return this.isLowData;\r\n  }\r\n\r\n  // Clear cache\r\n  clearCache(): void {\r\n    this.cache.clear();\r\n    // Clear localStorage cache\r\n    Object.keys(localStorage).forEach(key => {\r\n      if (key.startsWith('lowdata_')) {\r\n        localStorage.removeItem(key);\r\n      }\r\n    });\r\n    console.log('🧹 Low data cache cleared');\r\n  }\r\n\r\n  // Get cache stats\r\n  getCacheStats(): { size: number; keys: string[] } {\r\n    return {\r\n      size: this.cache.size,\r\n      keys: Array.from(this.cache.keys())\r\n    };\r\n  }\r\n}\r\n\r\nexport const lowDataOptimizer = LowDataOptimizer.getInstance();\r\n\r\n\r\n"],"names":[],"mappings":"AAAA,sEAAsE;AACtE,oDAAoD;;;;;AASpD,MAAM;IACJ,OAAe,SAA2B;IAClC,iBAAwC,KAAK;IAC7C,YAAY,MAAM;IAClB,QAAQ,IAAI,MAA6D;IAEjF,uCAAuC;IACtB,MAAM;QACrB,MAAM,IAAI,KAAK;QACf,MAAM,KAAK,KAAK;QAChB,WAAW,IAAI,KAAK,KAAK;QACzB,SAAS,KAAK,KAAK,KAAK,KAAO,wBAAwB;IACzD,EAAE;IAEF,OAAO,cAAgC;QACrC,IAAI,CAAC,iBAAiB,QAAQ,EAAE;YAC9B,iBAAiB,QAAQ,GAAG,IAAI;QAClC;QACA,OAAO,iBAAiB,QAAQ;IAClC;IAEA,OAAO;QACL,IAAI,CAAC,gBAAgB;QACrB,IAAI,CAAC,mBAAmB;QACxB,QAAQ,GAAG,CAAC;IACd;IAEQ,mBAAmB;QACzB,IAAI,gBAAgB,WAAW;YAC7B,MAAM,aAAa,AAAC,UAAkB,UAAU;YAChD,IAAI,CAAC,cAAc,GAAG;gBACpB,eAAe,WAAW,aAAa,IAAI;gBAC3C,UAAU,WAAW,QAAQ,IAAI;gBACjC,KAAK,WAAW,GAAG,IAAI;gBACvB,UAAU,WAAW,QAAQ,IAAI;YACnC;YAEA,6CAA6C;YAC7C,IAAI,CAAC,SAAS,GACZ,IAAI,CAAC,cAAc,CAAC,aAAa,KAAK,aACtC,IAAI,CAAC,cAAc,CAAC,aAAa,KAAK,QACtC,IAAI,CAAC,cAAc,CAAC,QAAQ,GAAG,KAC/B,IAAI,CAAC,cAAc,CAAC,QAAQ;YAE9B,QAAQ,GAAG,CAAC,2BAA2B;gBACrC,MAAM,IAAI,CAAC,cAAc,CAAC,aAAa;gBACvC,OAAO,IAAI,CAAC,cAAc,CAAC,QAAQ,GAAG;gBACtC,KAAK,IAAI,CAAC,cAAc,CAAC,GAAG,GAAG;gBAC/B,UAAU,IAAI,CAAC,cAAc,CAAC,QAAQ;gBACtC,WAAW,IAAI,CAAC,SAAS;YAC3B;YAEA,IAAI,IAAI,CAAC,SAAS,EAAE;gBAClB,QAAQ,GAAG,CAAC;YACd;QACF;IACF;IAEQ,sBAAsB;QAC5B,IAAI,gBAAgB,WAAW;YAC7B,MAAM,aAAa,AAAC,UAAkB,UAAU;YAChD,WAAW,gBAAgB,CAAC,UAAU;gBACpC,IAAI,CAAC,gBAAgB;YACvB;QACF;QAEA,mCAAmC;QACnC,OAAO,gBAAgB,CAAC,UAAU;YAChC,QAAQ,GAAG,CAAC;YACZ,IAAI,CAAC,gBAAgB;QACvB;QAEA,OAAO,gBAAgB,CAAC,WAAW;YACjC,QAAQ,GAAG,CAAC;YACZ,IAAI,CAAC,SAAS,GAAG;QACnB;IACF;IAEA,0CAA0C;IAC1C,cAAsB;QACpB,IAAI,CAAC,UAAU,MAAM,EAAE,OAAO,IAAI,CAAC,GAAG,CAAC,OAAO;QAC9C,IAAI,CAAC,IAAI,CAAC,cAAc,EAAE,OAAO,IAAI,CAAC,GAAG