irst load\r\n            if (typeof window !== 'undefined' && 'serviceWorker' in navigator) {\r\n              window.addEventListener('load', () => {\r\n                navigator.serviceWorker.register('/sw-optimized.js')\r\n                  .then((registration) => {\r\n                    console.log('⚡ Optimized Service Worker registered:', registration);\r\n                    registration.addEventListener('updatefound', () => {\r\n                      console.log('🔄 New service worker version found');\r\n                    });\r\n                  })\r\n                  .catch((error) => {\r\n                    console.warn('⚠️ Service Worker registration failed:', error);\r\n                  });\r\n              });\r\n            }\r\n\r\n            // Basic performance hook\r\n            if (typeof window !== 'undefined') {\r\n              window.addEventListener('load', () => {\r\n                console.log('🚀 PWA bootstrap complete');\r\n              });\r\n            }\r\n              `,\r\n            }}\r\n          />\r\n        )}\r\n        <ErrorBoundary>\r\n          <AuthProvider>\r\n            <AudioProvider>\r\n            <MediaProvider>\r\n              <SubscriptionProvider>\r\n                <ChatProvider>\r\n                  <AnalyticsProvider>\r\n                    <ActivityLogger>\r\n                      {/* <ScreenshotPrevention /> */}\r\n                      <main className=\"h-full w-full bg-gray-50\">\r\n                        {children}\r\n                      </main>\r\n                      {/* Browser will handle its own install prompt; custom UI removed */}\r\n                      <RealtimeNotifications />\r\n                      <PushNotificationListener />\r\n                      <NotificationUrlHandler />\r\n                      <OfflineIndicator />\r\n                      <FeatureUpdateChecker />\r\n                      <ForceUpdateButton />\r\n                    </ActivityLogger>\r\n                  </AnalyticsProvider>\r\n                </ChatProvider>\r\n              </SubscriptionProvider>\r\n            </MediaProvider>\r\n            </AudioProvider>\r\n          </AuthProvider>\r\n        </ErrorBoundary>\r\n      </body>\r\n    </html>\r\n  )\r\n}"],"names":[],"mappings":";;;;;;;;;AAIA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AAIA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;;;;;;;;;;;;;;;;;;;;;;;;;;;;AAEA,MAAM,eAAe,oDAAyB;AAE9C,4CAA4C;AAC5C;;AAoBA,+DAA+D;AAE/D,sCAAsC;AAEtC,gFAAgF;AAChF,MAAM,cAAc,SAAS,8CAA8C;AAEpE,MAAM,WAAqB;IAChC,cAAc,IAAI,IAAI,6DAAmC;IACzD,OAAO;IACP,aAAa;IACb,UAAU,CAAC,cAAc,CAAC;IAC1B,aAAa;QACX,SAAS;QACT,gBAAgB;QAChB,OAAO;IACT;IACA,iBAAiB;QACf,WAAW;IACb;IACA,iBAAiB;IACjB,WAAW;IACX,UAAU;QAAC;QAAU;QAAW;QAAa;QAAS;QAAa;QAAW;QAAS;QAAU;KAAY;IAC7G,SAAS;QAAC;YAAE,MAAM;QAAoB;KAAE;IACxC,SAAS;IACT,WAAW;IACX,QAAQ;IACR,WAAW;QACT,MAAM;QACN,UAAU;QACV,OAAO;QACP,aAAa;QACb,KAAK;QACL,QAAQ;YACN;gBACE,KAAK;gBACL,OAAO;gBACP,QAAQ;gBACR,KAAK;YACP;SACD;IACH;IACA,SAAS;QACP,MAAM;QACN,OAAO;QACP,aAAa;QACb,QAAQ;YAAC;SAA+B;IAC1C;AACF;AAEO,MAAM,WAAqB;IAChC,OAAO;IACP,cAAc;IACd,cAAc;IACd,cAAc;IACd,YAAY;IACZ,aAAa;AAEf;AAEe,SAAS,WAAW,EACjC,QAAQ,EAGT;IACC,qBACE,8OAAC;QAAK,MAAK;;0BACT,8OAAC;;kCACC,8OAAC;wBAAK,KAAI;wBAAO,MAAK;;;;;;kCACtB,8OAAC;wBAAK,KAAI;wBAAmB,MAAK;;;;;;kCAClC,8OAAC;wBAAK,KAAI;wBAAmB,OAAM;wBAAU,MAAK;;;;;;kCAClD,8OAAC;wBAAK,KAAI;wBAAmB,OAAM;wBAAU,MAAK;;;;;;kCAClD,8OAAC;wBAAK,KAAI;wBAAmB,OAAM;wBAAU,MAAK;;;;;;kCAGlD,8OAAC;wBAAK,KAAI;wBAAa,MAAK;;;;;;kCAC5B,8OAAC;wBAAK,KAAI;wBAAe,MAAK;;;;;;kCAC9B,8OAAC;wBAAK,KAAI;wBAAU,MAAK;wBAAY,IAAG;;;;;;kCACxC,8OAAC;wBAAK,KAAI;wBAAU,MAAK;wBAAW,IAAG;;;;;;kCACvC,8OAAC;wBAAK,KAAI;wBAAU,MAAK;wBAA+B,IAAG;;;;;;kCAG3D,8OAAC;wBAAK,KAAI;wBAAU,MAAK;wBAAmC,IAAG;;;;;;kCAC/D,8OAAC;wBAAK,KAAI;wBAAU,MAAK;wBAAkC,IAAG;;;;;;kCAI9D,8OAAC;wBAAK,MAAK;wBAAc,SAAQ;;;;;;kCACjC,8OAAC;wBAAK,MAAK;wBAA+B,SAAQ;;;;;;kCAClD,8OAAC;wBAAK,MAAK;wBAAwC,SAAQ;;;;;;kCAC3D,8OAAC;wBAAK,MAAK;wBAA6B,SAAQ;;;;;;kCAChD,8OAAC;wBAAK,MAAK;wBAAy