    {"offset": {"line": 424, "column": 0}, "map": {"version":3,"sources":["file:///home/eric/Loveworld-Singers-Rehearsal-Hub-Portal-Zonal-Mode/src/lib/performance-optimizer.ts"],"sourcesContent":["// Performance Optimizer - Fix PWA Slowness\nexport class PerformanceOptimizer {\n  // Disable heavy real-time subscriptions\n  static disableHeavyFeatures() {\n    // Disable real-time notifications\n    if (typeof window !== 'undefined') {\n      localStorage.setItem('disable_realtime', 'true')\n      localStorage.setItem('disable_chat', 'true')\n      localStorage.setItem('disable_notifications', 'true')\n    }\n  }\n\n  // Enable only essential features\n  static enableEssentialFeatures() {\n    if (typeof window !== 'undefined') {\n      localStorage.setItem('enable_caching', 'true')\n      localStorage.setItem('enable_offline', 'true')\n    }\n  }\n\n  // Clear heavy caches\n  static clearHeavyCaches() {\n    if (typeof window !== 'undefined') {\n      // Clear old caches\n      localStorage.removeItem('realtime_data')\n      localStorage.removeItem('chat_data')\n      localStorage.removeItem('notification_data')\n    }\n  }\n\n  // Optimize for speed\n  static optimizeForSpeed() {\n    this.disableHeavyFeatures()\n    this.enableEssentialFeatures()\n    this.clearHeavyCaches()\n    console.log('🚀 Performance optimized for speed!')\n  }\n\n  // Optimize for low data usage\n  static optimizeForLowData() {\n    if (typeof window !== 'undefined') {\n      // Enable data-saving features\n      localStorage.setItem('low_data_mode', 'true')\n      localStorage.setItem('disable_images', 'true')\n      localStorage.setItem('disable_videos', 'true')\n      localStorage.setItem('disable_animations', 'true')\n      localStorage.setItem('cache_aggressive', 'true')\n      \n      // Disable heavy features\n      localStorage.setItem('disable_realtime', 'true')\n      localStorage.setItem('disable_chat', 'true')\n      localStorage.setItem('disable_notifications', 'true')\n      \n      console.log('📱 Optimized for low data usage!')\n    }\n  }\n\n  // Auto-detect slow connection and optimize\n  static autoOptimize() {\n    if (typeof window !== 'undefined' && 'connection' in navigator) {\n      const connection = (navigator as any).connection\n      if (connection) {\n        const isSlowConnection = connection.effectiveType === 'slow-2g' || \n                               connection.effectiveType === '2g' ||\n                               connection.downlink < 1.5\n        \n        if (isSlowConnection) {\n          console.log('🐌 Slow connection detected, optimizing...')\n          this.optimizeForLowData()\n        }\n      }\n    }\n  }\n}\n\n"],"names":[],"mappings":"AAAA,2CAA2C;;;;;AACpC,MAAM;IACX,wCAAwC;IACxC,OAAO,uBAAuB;QAC5B,kCAAkC;QAClC;;IAKF;IAEA,iCAAiC;IACjC,OAAO,0BAA0B;QAC/B;;IAIF;IAEA,qBAAqB;IACrB,OAAO,mBAAmB;QACxB;;IAMF;IAEA,qBAAqB;IACrB,OAAO,mBAAmB;QACxB,IAAI,CAAC,oBAAoB;QACzB,IAAI,CAAC,uBAAuB;QAC5B,IAAI,CAAC,gBAAgB;QACrB,QAAQ,GAAG,CAAC;IACd;IAEA,8BAA8B;IAC9B,OAAO,qBAAqB;QAC1B;;IAeF;IAEA,2CAA2C;IAC3C,OAAO,eAAe;QACpB,IAAI,gBAAkB,eAAe,gBAAgB;;IAavD;AACF","debugId":null}},
    {"offset": {"line": 468, "column": 0}, "map": {"version":3,"sources":["file:///home/eric/Loveworld-Singers-Rehearsal-Hub-Portal-Zonal-Mode/src/utils/viewport-height-fix.ts"],"sourcesContent":["// Viewport Height Fix for Mobile Browsers\nexport class ViewportHeightFix {\n  private static isInitialized = false\n\n  static init() {\n    if (typeof window === 'undefined' || this.isInitialized) return\n    \n    this.isInitialized = true\n    \n    // Set CSS custom property for viewport height\n    const setVH = () => {\n      const vh = window.innerHeight * 0.01\n      document.documentElement.style.setProperty('--vh', `${vh}px`)\n      console.log('📱 Viewport height updated:', window.innerHeight, 'vh:', vh)\n    }\n\n    // Set initial value\n    setVH()\n\n    // Update on resize\n    window.addEventListener('resize', setVH)\n    \n    // Update on orientation change\n    window.addEventListener('orientationchange', () => {\n      setTimeout(setVH, 100)\n    })\n\n    // Update when visual viewport changes (mobile browsers)\n    if (window.visualViewport) {\n      window.visualViewport.addEventListener('resize', setVH)\n    }\n\n    // Handle app resume from background (iOS Safari issue)\n    document.addEventListener('visibilitychange', () => {\n      if (!document.hidden) {\n        console.log('📱 App resumed from background - fixing viewport')\n        setTimeout(setVH, 100)\n        setTimeout(setVH, 500) // Double check after animations\n      }\n    })\n\n    // Handle page focus (when switching back to tab)\n    window.addEventListener('focus', () => {\n      console.log('📱 Page focused - fixing viewport')\n      setTimeout(setVH, 100)\n    })\n\n    // Handle page show (when page becomes visible)\n    window.addEventListener('pageshow', (event) => {\n      if (event.persisted) {\n        console.log('📱 Page restored from cache - fixing viewport')\n        setTimeout(setVH, 100)\n      }\n    })\n\n    console.log('📱 Viewport height fix initialized')\n  }\n\n  static getViewportHeight() {\n    if (typeof window === 'undefined') return '100vh'\n    \n    // Use visual viewport if available\n    if (window.visualViewport) {\n      return `${window.visualViewport.height}px`\n    }\n    \n    // Use CSS custom property\n    const vh = document.documentElement.style.getPropertyValue('--vh')\n    if (vh) {\n      return `calc(var(--vh, 1vh) * 100)`\n    }\n    \n    return '100vh'\n  }\n\n  static forceRefresh() {\n    if (typeof window === 'undefined') return\n    \n    console.log('📱 Force refreshing viewport height')\n    const vh = window.innerHeight * 0.01\n    document.documentElement.style.setProperty('--vh', `${vh}px`)\n    \n    // Also trigger a resize event to update any components listening\n    window.dispatchEvent(new Event('resize'))\n  }\n}\n\n\n\n"],"names":[],"mappings":"AAAA,0CAA0C;;;;;AACnC,MAAM;IACX,OAAe,gBAAgB,MAAK;IAEpC,OAAO,OAAO;QACZ,IAAI,gBAAkB,eAAe,IAAI,CAAC,aAAa,EAAE;;;QAIzD,8CAA8C;QAC9C,MAAM;IA8CR;IAEA,OAAO,oBAAoB;QACzB,wCAAmC,OAAO;;;QAO1C,0BAA0B;QAC1B,MAAM;IAMR;IAEA,OAAO,eAAe;QACpB,wCAAmC;;;QAGnC,MAAM;IAKR;AACF","debugId":null}},
    {"offset": {"line": 500, "column": 0}, "map": {"version":3,"sources":["file:///home/eric/Loveworld-Singers-Rehearsal-Hub-Portal-Zonal-Mode/src/utils/navigation.ts"],"sourcesContent":["// Navigation Utilities for Better Back Navigation\nexport class NavigationManager {\n  private static navigationHistory: string[] = []\n  private static isInitialized = false\n\n  static init() {\n    if (typeof window === 'undefined' || this.isInitialized) return\n    \n    this.isInitialized = true\n    \n    // Track navigation history\n    this.navigationHistory.push(window.location.pathname)\n    \n    // Listen for navigation changes\n    const originalPushState = history.pushState\n    const originalReplaceState = history.replaceState\n    \n    history.pushState = function(...args) {\n      originalPushState.apply(history, args)\n      NavigationManager.trackNavigation()\n    }\n    \n    history.replaceState = function(...args) {\n      originalReplaceState.apply(history, args)\n      NavigationManager.trackNavigation()\n    }\n    \n    // Listen for popstate (back/forward buttons)\n    window.addEventListener('popstate', () => {\n      NavigationManager.trackNavigation()\n    })\n    \n    console.log('🧭 Navigation manager initialized')\n  }\n\n  private static trackNavigation() {\n    const currentPath = window.location.pathname\n    const lastPath = this.navigationHistory[this.navigationHistory.length - 1]\n    \n    // Only add if it's different from the last path\n    if (currentPath !== lastPath) {\n      this.navigationHistory.push(currentPath)\n      \n      // Keep only last 10 entries to prevent memory issues\n      if (this.navigationHistory.length > 10) {\n        this.navigationHistory = this.navigationHistory.slice(-10)\n      }\n    }\n  }\n\n  static getPreviousPage(): string | null {\n    if (this.navigationHistory.length < 2) return null\n    \n    const previousPage = this.navigationHistory[this.navigationHistory.length - 2]\n    \n    // Don't go back to auth pages\n    if (previousPage === '/auth' || previousPage.startsWith('/auth/')) {\n      return this.getSafeFallback()\n    }\n    \n    return previousPage\n  }\n\n  static getSafeFallback(): string {\n    // Check if user is admin\n    const isAdmin = typeof window !== 'undefined' && localStorage.getItem('adminAuthenticated') === 'true'\n    \n    if (isAdmin) {\n      return '/admin'\n    }\n    \n    // Check if user is authenticated - be more lenient\n    const isAuthenticated = typeof window !== 'undefined' && (\n      localStorage.getItem('userAuthenticated') === 'true' ||\n      localStorage.getItem('hasCompletedProfile') === 'true' ||\n      localStorage.getItem('bypassLogin') === 'true'\n    )\n    \n    if (isAuthenticated) {\n      return '/home'\n    }\n    \n    return '/auth'\n  }\n\n  static safeBack(router: any) {\n    const previousPage = this.getPreviousPage()\n    \n    if (previousPage) {\n      console.log('🧭 Navigating back to:', previousPage)\n      router.push(previousPage)\n    } else {\n      console.log('🧭 No safe back page, using fallback')\n      router.push(this.getSafeFallback())\n    }\n  }\n\n  static getNavigationHistory(): string[] {\n    return [...this.navigationHistory]\n  }\n}\n"],"names":[],"mappings":"AAAA,kDAAkD;;;;;AAC3C,MAAM;IACX,OAAe,oBAA8B,EAAE,CAAA;IAC/C,OAAe,gBAAgB,MAAK;IAEpC,OAAO,OAAO;QACZ,IAAI,gBAAkB,eAAe,IAAI,CAAC,aAAa,EAAE;;;QAOzD,gCAAgC;QAChC,MAAM;QACN,MAAM;IAkBR;IAEA,OAAe,kBAAkB;QAC/B,MAAM,cAAc,OAAO,QAAQ,CAAC,QAAQ;QAC5C,MAAM,WAAW,IAAI,CAAC,iBAAiB,CAAC,IAAI,CAAC,iBAAiB,CAAC,MAAM,GAAG,EAAE;QAE1E,gDAAgD;QAChD,IAAI,gBAAgB,UAAU;YAC5B,IAAI,CAAC,iBAAiB,CAAC,IAAI,CAAC;YAE5B,qDAAqD;YACrD,IAAI,IAAI,CAAC,iBAAiB,CAAC,MAAM,GAAG,IAAI;gBACtC,IAAI,CAAC,iBAAiB,GAAG,IAAI,CAAC,iBAAiB,CAAC,KAAK,CAAC,CAAC;YACzD;QACF;IACF;IAEA,OAAO,kBAAiC;QACtC,IAAI,IAAI,CAAC,iBAAiB,CAAC,MAAM,GAAG,GAAG,OAAO;QAE9C,MAAM,eAAe,IAAI,CAAC,iBAAiB,CAAC,IAAI,CAAC,iBAAiB,CAAC,MAAM,GAAG,EAAE;QAE9E,8BAA8B;QAC9B,IAAI,iBAAiB,WAAW,aAAa,UAAU,CAAC,WAAW;YACjE,OAAO,IAAI,CAAC,eAAe;QAC7B;QAEA,OAAO;IACT;IAEA,OAAO,kBAA0B;QAC/B,yBAAyB;QACzB,MAAM,UAAU,gBAAkB,eAAe,aAAa,OAAO,CAAC,0BAA0B;QAEhG;;QAIA,mDAAmD;QACnD,MAAM,kBAAkB,gBAAkB,eAAe,CACvD,aAAa,OAAO,CAAC,yBAAyB,UAC9C,aAAa,OAAO,CAAC,2BAA2B,UAChD,aAAa,OAAO,CAAC,mBAAmB,MAC1C;QAEA;;QAIA,OAAO;IACT;IAEA,OAAO,SAAS,MAAW,EAAE;QAC3B,MAAM,eAAe,IAAI,CAAC,eAAe;QAEzC,IAAI,cAAc;YAChB,QAAQ,GAAG,CAAC,0BAA0B;YACtC,OAAO,IAAI,CAAC;QACd,OAAO;YACL,QAAQ,GAAG,CAAC;YACZ,OAAO,IAAI,CAAC,IAAI,CAAC,eAAe;QAClC;IACF;IAEA,OAAO,uBAAiC;QACtC,OAAO;eAAI,IAAI,CAAC,iBAAiB;SAAC;IACpC;AACF","debugId":null}},
    {"offset": {"line": 568, "column": 0}, "map": {"version":3,"sources":["file:///home/eric/Loveworld-Singers-Rehearsal-Hub-Portal-Zonal-Mode/src/utils/safe-area-utils.ts"],"sourcesContent":["// Safe Area Utilities for PWA\nexport class SafeAreaUtils {\n  private static isInitialized = false\n\n  static init() {\n    if (typeof window === 'undefined' || this.isInitialized) return\n    \n    this.isInitialized = true\n    \n    // Set CSS custom properties for safe areas\n    const updateSafeAreas = () => {\n      const safeAreaTop = getComputedStyle(document.documentElement)\n        .getPropertyValue('--safe-area-inset-top') || '0px'\n      const safeAreaBottom = getComputedStyle(document.documentElement)\n        .getPropertyValue('--safe-area-inset-bottom') || '0px'\n      const safeAreaLeft = getComputedStyle(document.documentElement)\n        .getPropertyValue('--safe-area-inset-left') || '0px'\n      const safeAreaRight = getComputedStyle(document.documentElement)\n        .getPropertyValue('--safe-area-inset-right') || '0px'\n\n      // Set enhanced safe area values with minimum padding\n      const enhancedBottom = Math.max(\n        parseInt(safeAreaBottom) || 0,\n        window.innerHeight < 600 ? 24 : 20 // More padding on smaller screens\n      )\n      \n      document.documentElement.style.setProperty('--enhanced-safe-area-bottom', `${enhancedBottom}px`)\n      \n      console.log('📱 Safe areas updated:', {\n        top: safeAreaTop,\n        bottom: safeAreaBottom,\n        left: safeAreaLeft,\n        right: safeAreaRight,\n        enhancedBottom\n      })\n    }\n\n    // Set initial values\n    updateSafeAreas()\n\n    // Update on resize\n    window.addEventListener('resize', updateSafeAreas)\n    \n    // Update on orientation change\n    window.addEventListener('orientationchange', () => {\n      setTimeout(updateSafeAreas, 100)\n    })\n\n    // Update when visual viewport changes (mobile browsers)\n    if (window.visualViewport) {\n      window.visualViewport.addEventListener('resize', updateSafeAreas)\n    }\n\n    // Handle app resume from background\n    document.addEventListener('visibilitychange', () => {\n      if (!document.hidden) {\n        setTimeout(updateSafeAreas, 100)\n      }\n    })\n\n    console.log('📱 Safe area utils initialized')\n  }\n\n  static getSafeAreaBottom() {\n    if (typeof window === 'undefined') return '20px'\n    \n    const enhancedBottom = document.documentElement.style.getPropertyValue('--enhanced-safe-area-bottom')\n    return enhancedBottom || '20px'\n  }\n\n  static isSmallScreen() {\n    if (typeof window === 'undefined') return false\n    return window.innerHeight < 600\n  }\n\n  static isVerySmallScreen() {\n    if (typeof window === 'undefined') return false\n    return window.innerHeight < 500\n  }\n\n  static getRecommendedBottomPadding() {\n    if (this.isVerySmallScreen()) return '32px'\n    if (this.isSmallScreen()) return '28px'\n    return '24px'\n  }\n}\n"],"names":[],"mappings":"AAAA,8BAA8B;;;;;AACvB,MAAM;IACX,OAAe,gBAAgB,MAAK;IAEpC,OAAO,OAAO;QACZ,IAAI,gBAAkB,eAAe,IAAI,CAAC,aAAa,EAAE;;;QAIzD,2CAA2C;QAC3C,MAAM;IAmDR;IAEA,OAAO,oBAAoB;QACzB,wCAAmC,OAAO;;;QAE1C,MAAM;IAER;IAEA,OAAO,gBAAgB;QACrB,wCAAmC,OAAO;;;IAE5C;IAEA,OAAO,oBAAoB;QACzB,wCAAmC,OAAO;;;IAE5C;IAEA,OAAO,8BAA8B;QACnC,IAAI,IAAI,CAAC,iBAAiB,IAAI,OAAO;QACrC,IAAI,IAAI,CAAC,aAAa,IAAI,OAAO;QACjC,OAAO;IACT;AACF","debugId":null}},
