    {"offset": {"line": 728, "column": 0}, "map": {"version":3,"sources":["file:///home/eric/Loveworld-Singers-Rehearsal-Hub-Portal-Zonal-Mode/src/lib/firebase-setup.ts"],"sourcesContent":["import { initializeApp, getApp, FirebaseApp } from 'firebase/app'\nimport { getAuth, setPersistence, browserLocalPersistence } from 'firebase/auth'\nimport { initializeFirestore, getFirestore, Firestore } from 'firebase/firestore'\nimport { getStorage } from 'firebase/storage'\nimport { getDatabase, Database } from 'firebase/database'\n\nconst firebaseConfig = {\n  apiKey: process.env.NEXT_PUBLIC_FIREBASE_API_KEY || '',\n  authDomain: process.env.NEXT_PUBLIC_FIREBASE_AUTH_DOMAIN || '',\n  databaseURL: process.env.NEXT_PUBLIC_FIREBASE_DATABASE_URL || '',\n  projectId: process.env.NEXT_PUBLIC_FIREBASE_PROJECT_ID || '',\n  storageBucket: process.env.NEXT_PUBLIC_FIREBASE_STORAGE_BUCKET || '',\n  messagingSenderId: process.env.NEXT_PUBLIC_FIREBASE_MESSAGING_SENDER_ID || '',\n  appId: process.env.NEXT_PUBLIC_FIREBASE_APP_ID || '',\n  measurementId: process.env.NEXT_PUBLIC_FIREBASE_MEASUREMENT_ID || ''\n}\n\nif (!firebaseConfig.apiKey || !firebaseConfig.projectId) {\n  throw new Error('Firebase configuration missing. Check .env.local file.')\n}\n\nlet app: FirebaseApp\ntry {\n  app = initializeApp(firebaseConfig)\n} catch (error: any) {\n  if (error.code === 'app/duplicate-app') {\n    app = getApp()\n  } else {\n    throw error\n  }\n}\n\nexport const auth = getAuth(app)\n\nexport const db: Firestore = (() => {\n  try {\n    return initializeFirestore(app, {\n      experimentalForceLongPolling: false,\n      experimentalAutoDetectLongPolling: true,\n      localCache: { kind: 'persistent' }\n    })\n  } catch (error: any) {\n    if (error.code === 'firestore/already-exists') {\n      return getFirestore(app)\n    }\n    throw error\n  }\n})()\n\nexport const storage = getStorage(app)\n\nlet _realtimeDb: Database | null = null;\n\nexport const realtimeDb: Database | null = (() => {\n  if (typeof window !== 'undefined') { // Only initialize on client side\n    try {\n      if (!_realtimeDb) {\n        _realtimeDb = getDatabase(app);\n      }\n      return _realtimeDb;\n    } catch (error) {\n      console.warn('Failed to initialize Realtime Database:', error);\n      return null;\n    }\n  } else {\n    // Return null on server-side to prevent build failures\n    return null;\n  }\n})()\n\nexport function isRealtimeDbAvailable(): boolean {\n  return realtimeDb !== null;\n}\n\nif (typeof window !== 'undefined') {\n  setPersistence(auth, browserLocalPersistence).catch(console.error)\n}\n\nexport default app\n"],"names":[],"mappings":";;;;;;;;;;;;;;AAAA;AAAA;AACA;AAAA;AACA;AAAA;AACA;AAAA;AACA;;;;;;AAEA,MAAM,iBAAiB;IACrB,QAAQ,+EAA4C;IACpD,YAAY,6EAAgD;IAC5D,aAAa,iGAAiD;IAC9D,WAAW,6DAA+C;IAC1D,eAAe,iFAAmD;IAClE,mBAAmB,oDAAwD;IAC3E,OAAO,iFAA2C;IAClD,eAAe,oDAAmD;AACpE;AAEA,IAAI,CAAC,eAAe,MAAM,IAAI,CAAC,eAAe,SAAS,EAAE;IACvD,MAAM,IAAI,MAAM;AAClB;AAEA,IAAI;AACJ,IAAI;IACF,MAAM,IAAA,iLAAa,EAAC;AACtB,EAAE,OAAO,OAAY;IACnB,IAAI,MAAM,IAAI,KAAK,qBAAqB;QACtC,MAAM,IAAA,0KAAM;IACd,OAAO;QACL,MAAM;IACR;AACF;AAEO,MAAM,OAAO,IAAA,6KAAO,EAAC;AAErB,MAAM,KAAgB,CAAC;IAC5B,IAAI;QACF,OAAO,IAAA,oNAAmB,EAAC,KAAK;YAC9B,8BAA8B;YAC9B,mCAAmC;YACnC,YAAY;gBAAE,MAAM;YAAa;QACnC;IACF,EAAE,OAAO,OAAY;QACnB,IAAI,MAAM,IAAI,KAAK,4BAA4B;YAC7C,OAAO,IAAA,6MAAY,EAAC;QACtB;QACA,MAAM;IACR;AACF,CAAC;AAEM,MAAM,UAAU,IAAA,kMAAU,EAAC;AAElC,IAAI,cAA+B;AAE5B,MAAM,aAA8B,CAAC;IAC1C;;SAUO;QACL,uDAAuD;QACvD,OAAO;IACT;AACF,CAAC;AAEM,SAAS;IACd,OAAO,eAAe;AACxB;AAEA;;uCAIe","debugId":null}},
    {"offset": {"line": 816, "column": 0}, "map": {"version":3,"sources":["file:///home/eric/Loveworld-Singers-Rehearsal-Hub-Portal-Zonal-Mode/src/lib/session-manager.ts"],"sourcesContent":["// Session Management Service - Concurrent Login Prevention\nimport { doc, setDoc, getDoc, onSnapshot, deleteDoc, serverTimestamp } from 'firebase/firestore'\nimport { db } from './firebase-setup'\nimport { User } from 'firebase/auth'\n\ninterface UserSession {\n  userId: string\n  deviceId: string\n  deviceInfo: string\n  deviceModel: string\n  browserInfo: string\n  osInfo: string\n  loginTime: any\n  lastActivity: any\n  isActive: boolean\n  terminatedAt?: any\n  terminatedByDeviceId?: string\n  terminatedReason?: string\n}\n\nexport class SessionManager {\n  private static deviceId: string = ''\n  private static sessionListener: (() => void) | null = null\n  \n  // Generate unique device ID\n  static generateDeviceId(): string {\n    if (this.deviceId) return this.deviceId\n    \n    // Create unique device fingerprint\n    const canvas = document.createElement('canvas')\n    const ctx = canvas.getContext('2d')\n    ctx!.textBaseline = 'top'\n    ctx!.font = '14px Arial'\n    ctx!.fillText('Device fingerprint', 2, 2)\n    \n    const fingerprint = canvas.toDataURL()\n    const userAgent = navigator.userAgent\n    const screen = `${window.screen.width}x${window.screen.height}`\n    const timezone = Intl.DateTimeFormat().resolvedOptions().timeZone\n    \n    this.deviceId = btoa(`${fingerprint}-${userAgent}-${screen}-${timezone}`).slice(0, 32)\n    return this.deviceId\n  }\n  \n  // Get device info for display\n  static getDeviceInfo(): string {\n    const userAgent = navigator.userAgent\n    let deviceInfo = 'Unknown Device'\n    \n    if (/iPhone|iPad|iPod/.test(userAgent)) {\n      deviceInfo = 'iPhone/iPad'\n    } else if (/Android/.test(userAgent)) {\n      deviceInfo = 'Android Device'\n    } else if (/Windows/.test(userAgent)) {\n      deviceInfo = 'Windows PC'\n    } else if (/Mac/.test(userAgent)) {\n      deviceInfo = 'Mac'\n    } else if (/Linux/.test(userAgent)) {\n      deviceInfo = 'Linux PC'\n    }\n    \n    // Add browser info\n    if (/Chrome/.test(userAgent)) deviceInfo += ' (Chrome)'\n    else if (/Firefox/.test(userAgent)) deviceInfo += ' (Firefox)'\n    else if (/Safari/.test(userAgent)) deviceInfo += ' (Safari)'\n    else if (/Edge/.test(userAgent)) deviceInfo += ' (Edge)'\n    \n    // Add specific device model if available\n    const deviceModel = this.getDeviceModel(userAgent)\n    if (deviceModel) {\n      deviceInfo = deviceModel + ' ' + deviceInfo\n    }\n    \n    return deviceInfo\n  }\n  \n  // Get specific device model\n  static getDeviceModel(userAgent: string): string | null {\n    // Samsung devices\n    const samsungMatch = userAgent.match(/SM-[A-Z0-9]+/)\n    if (samsungMatch) {\n      return `Samsung ${samsungMatch[0]}`\n    }\n    \n    // Itel devices\n    const itelMatch = userAgent.match(/itel[ _][A-Z0-9]+/i)\n    if (itelMatch) {\n      return itelMatch[0].replace(/_/g, ' ')\n    }\n    \n    // Other Android devices\n    const androidMatch = userAgent.match(/Android.*?([A-Za-z0-9 ]+?)(?:Build|;)/)\n    if (androidMatch) {\n      return androidMatch[1].trim()\n    }\n    \n    return null\n  }\n  \n  // Get browser information\n  static getBrowserInfo(): string {\n    const userAgent = navigator.userAgent\n    if (/Chrome/.test(userAgent)) return 'Chrome'\n    if (/Firefox/.test(userAgent)) return 'Firefox'\n    if (/Safari/.test(userAgent)) return 'Safari'\n    if (/Edge/.test(userAgent)) return 'Edge'\n    return 'Unknown Browser'\n  }\n  \n  // Get OS information\n  static getOSInfo(): string {\n    const userAgent = navigator.userAgent\n    if (/Windows/.test(userAgent)) return 'Windows'\n    if (/Mac/.test(userAgent)) return 'macOS'\n    if (/Linux/.test(userAgent)) return 'Linux'\n    if (/Android/.test(userAgent)) return 'Android'\n    if (/iPhone|iPad|iPod/.test(userAgent)) return 'iOS'\n    return 'Unknown OS'\n  }\n  \n  // Check if user can login (Single-device policy - block new login if another device active)\n  static async canUserLogin(userId: string): Promise<{ canLogin: boolean; activeDevice?: string }> {\n    try {\n      const currentDeviceId = this.generateDeviceId()\n      const sessionRef = doc(db, 'user_sessions', userId)\n      const sessionDoc = await getDoc(sessionRef)\n\n      if (!sessionDoc.exists()) {\n        return { canLogin: true }\n      }\n\n      const session = sessionDoc.data() as UserSession\n      if (session.isActive && session.deviceId && session.deviceId !== currentDeviceId) {\n        return { canLogin: false, activeDevice: session.deviceInfo || 'another device' }\n      }\n\n      return { canLogin: true }\n    } catch (_e) {\n    return { canLogin: true }\n    }\n  }\n  \n  // Create new session for user (terminates existing sessions)\n  static async createSession(user: User): Promise<void> {\n    try {\n      const deviceId = this.generateDeviceId()\n      const deviceInfo = this.getDeviceInfo()\n      const deviceModel = this.getDeviceModel(navigator.userAgent) || 'Unknown'\n      const browserInfo = this.getBrowserInfo()\n      const osInfo = this.getOSInfo()\n      \n      // Terminate any existing session for this user\n      await this.terminateExistingSession(user.uid, deviceId)\n      \n      const session: UserSession = {\n        userId: user.uid,\n        deviceId,\n        deviceInfo,\n        deviceModel,\n        browserInfo,\n        osInfo,\n        loginTime: serverTimestamp(),\n        lastActivity: serverTimestamp(),\n        isActive: true\n      }\n      \n      const sessionRef = doc(db, 'user_sessions', user.uid)\n      await setDoc(sessionRef, session)\n      \n      // Start activity tracking\n      this.startActivityTracking(user.uid)\n      \n      console.log('✅ Session created for device:', deviceInfo)\n    } catch (error) {\n      console.error('Error creating session:', error)\n    }\n  }\n  \n  // Terminate existing session for user (Facebook-style)\n  static async terminateExistingSession(userId: string, currentDeviceId: string): Promise<void> {\n    try {\n      const sessionRef = doc(db, 'user_sessions', userId)\n      const sessionDoc = await getDoc(sessionRef)\n      \n      if (sessionDoc.exists()) {\n        const session = sessionDoc.data() as UserSession\n        \n        // If existing session is on a different device, notify it\n        if (session.deviceId !== currentDeviceId) {\n          // Update the session to mark it as terminated\n          await setDoc(sessionRef, {\n            ...session,\n            isActive: false,\n            terminatedAt: serverTimestamp(),\n            terminatedByDeviceId: currentDeviceId\n          }, { merge: true })\n        }\n      }\n    } catch (error) {\n      console.error('Error terminating existing session:', error)\n    }\n  }\n  \n  // Update last activity\n  static async updateActivity(userId: string): Promise<void> {\n    try {\n      const sessionRef = doc(db, 'user_sessions', userId)\n      await setDoc(sessionRef, {\n        lastActivity: serverTimestamp()\n      }, { merge: true })\n    } catch (error) {\n      console.error('Error updating activity:', error)\n    }\n  }\n  \n  // Start tracking user activity\n  static startActivityTracking(userId: string): void {\n    // DISABLED - Session tracking causes page reloads\n    // Just log the activity without forcing logouts\n    console.log('📊 Activity tracking disabled to prevent reloads')\n  }\n  \n  // Handle session termination (user logged in elsewhere)\n  static handleSessionTermination(): void {\n    // DISABLED - No more forced reloads\n    // Just clear the session silently, let React handle the UI\n    console.log('⚠️ Session terminated on another device')\n  }\n  \n  // End session\n  static async endSession(userId: string): Promise<void> {\n    try {\n      const sessionRef = doc(db, 'user_sessions', userId)\n      await deleteDoc(sessionRef)\n      \n      if (this.sessionListener) {\n        this.sessionListener()\n        this.sessionListener = null\n      }\n      \n      console.log('✅ Session ended')\n    } catch (error) {\n      console.error('Error ending session:', error)\n    }\n  }\n  \n  // Force logout user from all devices (admin function)\n  static async forceLogoutUser(userId: string): Promise<void> {\n    try {\n      const sessionRef = doc(db, 'user_sessions', userId)\n      await setDoc(sessionRef, {\n        isActive: false,\n        terminatedAt: serverTimestamp(),\n        terminatedReason: 'admin_force_logout'\n      }, { merge: true })\n      console.log('✅ User force logged out from all devices')\n    } catch (error) {\n      console.error('Error force logging out user:', error)\n    }\n  }\n}"],"names":[],"mappings":"AAAA,2DAA2D;;;;;AAC3D;AAAA;AACA;;;AAkBO,MAAM;IACX,OAAe,WAAmB,GAAE;IACpC,OAAe,kBAAuC,KAAI;IAE1D,4BAA4B;IAC5B,OAAO,mBAA2B;QAChC,IAAI,IAAI,CAAC,QAAQ,EAAE,OAAO,IAAI,CAAC,QAAQ;QAEvC,mCAAmC;QACnC,MAAM,SAAS,SAAS,aAAa,CAAC;QACtC,MAAM,MAAM,OAAO,UAAU,CAAC;QAC9B,IAAK,YAAY,GAAG;QACpB,IAAK,IAAI,GAAG;QACZ,IAAK,QAAQ,CAAC,sBAAsB,GAAG;QAEvC,MAAM,cAAc,OAAO,SAAS;QACpC,MAAM,YAAY,UAAU,SAAS;QACrC,MAAM,SAAS,GAAG,OAAO,MAAM,CAAC,KAAK,CAAC,CAAC,EAAE,OAAO,MAAM,CAAC,MAAM,EAAE;QAC/D,MAAM,WAAW,KAAK,cAAc,GAAG,eAAe,GAAG,QAAQ;QAEjE,IAAI,CAAC,QAAQ,GAAG,KAAK,GAAG,YAAY,CAAC,EAAE,UAAU,CAAC,EAAE,OAAO,CAAC,EAAE,UAAU,EAAE,KAAK,CAAC,GAAG;QACnF,OAAO,IAAI,CAAC,QAAQ;IACtB;IAEA,8BAA8B;IAC9B,OAAO,gBAAwB;QAC7B,MAAM,YAAY,UAAU,SAAS;QACrC,IAAI,aAAa;QAEjB,IAAI,mBAAmB,IAAI,CAAC,YAAY;YACtC,aAAa;QACf,OAAO,IAAI,UAAU,IAAI,CAAC,YAAY;YACpC,aAAa;QACf,OAAO,IAAI,UAAU,IAAI,CAAC,YAAY;YACpC,aAAa;QACf,OAAO,IAAI,MAAM,IAAI,CAAC,YAAY;YAChC,aAAa;QACf,OAAO,IAAI,QAAQ,IAAI,CAAC,YAAY;YAClC,aAAa;QACf;QAEA,mBAAmB;QACnB,IAAI,SAAS,IAAI,CAAC,YAAY,cAAc;aACvC,IAAI,UAAU,IAAI,CAAC,YAAY,cAAc;aAC7C,IAAI,SAAS,IAAI,CAAC,YAAY,cAAc;aAC5C,IAAI,OAAO,IAAI,CAAC,YAAY,cAAc;QAE/C,yCAAyC;QACzC,MAAM,cAAc,IAAI,CAAC,cAAc,CAAC;QACxC,IAAI,aAAa;YACf,aAAa,cAAc,MAAM;QACnC;QAEA,OAAO;IACT;IAEA,4BAA4B;IAC5B,OAAO,eAAe,SAAiB,EAAiB;QACtD,kBAAkB;QAClB,MAAM,eAAe,UAAU,KAAK,CAAC;QACrC,IAAI,cAAc;YAChB,OAAO,CAAC,QAAQ,EAAE,YAAY,CAAC,EAAE,EAAE;QACrC;QAEA,eAAe;QACf,MAAM,YAAY,UAAU,KAAK,CAAC;QAClC,IAAI,WAAW;YACb,OAAO,SAAS,CAAC,EAAE,CAAC,OAAO,CAAC,MAAM;QACpC;QAEA,wBAAwB;QACxB,MAAM,eAAe,UAAU,KAAK,CAAC;QACrC,IAAI,cAAc;YAChB,OAAO,YAAY,CAAC,EAAE,CAAC,IAAI;QAC7B;QAEA,OAAO;IACT;IAEA,0BAA0B;IAC1B,OAAO,iBAAyB;QAC9B,MAAM,YAAY,UAAU,SAAS;QACrC,IAAI,SAAS,IAAI,CAAC,YAAY,OAAO;QACrC,IAAI,UAAU,IAAI,CAAC,YAAY,OAAO;QACtC,IAAI,SAAS,IAAI,CAAC,YAAY,OAAO;QACrC,IAAI,OAAO,IAAI,CAAC,YAAY,OAAO;QACnC,OAAO;IACT;IAEA,qBAAqB;IACrB,OAAO,YAAoB;QACzB,MAAM,YAAY,UAAU,SAAS;QACrC,IAAI,UAAU,IAAI,CAAC,YAAY,OAAO;QACtC,IAAI,MAAM,IAAI,CAAC,YAAY,OAAO;QAClC,IAAI,QAAQ,IAAI,CAAC,YAAY,OAAO;QACpC,IAAI,UAAU,IAAI,CAAC,YAAY,OAAO;QACtC,IAAI,mBAAmB,IAAI,CAAC,YAAY,OAAO;QAC/C,OAAO;IACT;IAEA,4FAA4F;IAC5F,aAAa,aAAa,MAAc,EAAyD;QAC/F,IAAI;YACF,MAAM,kBAAkB,IAAI,CAAC,gBAAgB;YAC7C,MAAM,aAAa,IAAA,oMAAG,EAAC,qIAAE,EAAE,iBAAiB;YAC5C,MAAM,aAAa,MAAM,IAAA,uMAAM,EAAC;YAEhC,IAAI,CAAC,WAAW,MAAM,IAAI;gBACxB,OAAO;oBAAE,UAAU;gBAAK;YAC1B;YAEA,MAAM,UAAU,WAAW,IAAI;YAC/B,IAAI,QAAQ,QAAQ,IAAI,QAAQ,QAAQ,IAAI,QAAQ,QAAQ,KAAK,iBAAiB;gBAChF,OAAO;oBAAE,UAAU;oBAAO,cAAc,QAAQ,UAAU,IAAI;gBAAiB;YACjF;YAEA,OAAO;gBAAE,UAAU;YAAK;QAC1B,EAAE,OAAO,IAAI;YACb,OAAO;gBAAE,UAAU;YAAK;QACxB;IACF;IAEA,6DAA6D;IAC7D,aAAa,cAAc,IAAU,EAAiB;QACpD,IAAI;YACF,MAAM,WAAW,IAAI,CAAC,gBAAgB;YACtC,MAAM,aAAa,IAAI,CAAC,aAAa;YACrC,MAAM,cAAc,IAAI,CAAC,cAAc,CAAC,UAAU,SAAS,KAAK;YAChE,MAAM,cAAc,IAAI,CAAC,cAAc;YACvC,MAAM,SAAS,IAAI,CAAC,SAAS;YAE7B,+CAA+C;YAC/C,MAAM,IAAI,CAAC,wBAAwB,CAAC,KAAK,GAAG,EAAE;YAE9C,MAAM,UAAuB;gBAC3B,QAAQ,KAAK,GAAG;gBAChB;gBACA;gBACA;gBACA;gBACA;gBACA,WAAW,IAAA,gNAAe;gBAC1B,cAAc,IAAA,gNAAe;gBAC7B,UAAU;YACZ;YAEA,MAAM,aAAa,IAAA,oMAAG,EAAC,qIAAE,EAAE,iBAAiB,KAAK,GAAG;YACpD,MAAM,IAAA,uMAAM,EAAC,YAAY;YAEzB,0BAA0B;YAC1B,IAAI,CAAC,qBAAqB,CAAC,KAAK,GAAG;YAEnC,QAAQ,GAAG,CAAC,iCAAiC;QAC/C,EAAE,OAAO,OAAO;YACd,QAAQ,KAAK,CAAC,2BAA2B;QAC3C;IACF;IAEA,uDAAuD;IACvD,aAAa,yBAAyB,MAAc,EAAE,eAAuB,EAAiB;QAC5F,IAAI;YACF,MAAM,aAAa,IAAA,oMAAG,EAAC,qIAAE,EAAE,iBAAiB;YAC5C,MAAM,aAAa,MAAM,IAAA,uMAAM,EAAC;YAEhC,IAAI,WAAW,MAAM,IAAI;gBACvB,MAAM,UAAU,WAAW,IAAI;gBAE/B,0DAA0D;gBAC1D,IAAI,QAAQ,QAAQ,KAAK,iBAAiB;oBACxC,8CAA8C;oBAC9C,MAAM,IAAA,uMAAM,EAAC,YAAY;wBACvB,GAAG,OAAO;wBACV,UAAU;wBACV,cAAc,IAAA,gNAAe;wBAC7B,sBAAsB;oBACxB,GAAG;wBAAE,OAAO;oBAAK;gBACnB;YACF;QACF,EAAE,OAAO,OAAO;YACd,QAAQ,KAAK,CAAC,uCAAuC;QACvD;IACF;IAEA,uBAAuB;IACvB,aAAa,eAAe,MAAc,EAAiB;QACzD,IAAI;YACF,MAAM,aAAa,IAAA,oMAAG,EAAC,qIAAE,EAAE,iBAAiB;YAC5C,MAAM,IAAA,uMAAM,EAAC,YAAY;gBACvB,cAAc,IAAA,gNAAe;YAC/B,GAAG;gBAAE,OAAO;YAAK;QACnB,EAAE,OAAO,OAAO;YACd,QAAQ,KAAK,CAAC,4BAA4B;QAC5C;IACF;IAEA,+BAA+B;IAC/B,OAAO,sBAAsB,MAAc,EAAQ;QACjD,kDAAkD;QAClD,gDAAgD;QAChD,QAAQ,GAAG,CAAC;IACd;IAEA,wDAAwD;IACxD,OAAO,2BAAiC;QACtC,oCAAoC;QACpC,2DAA2D;QAC3D,QAAQ,GAAG,CAAC;IACd;IAEA,cAAc;IACd,aAAa,WAAW,MAAc,EAAiB;QACrD,IAAI;YACF,MAAM,aAAa,IAAA,oMAAG,EAAC,qIAAE,EAAE,iBAAiB;YAC5C,MAAM,IAAA,0MAAS,EAAC;YAEhB,IAAI,IAAI,CAAC,eAAe,EAAE;gBACxB,IAAI,CAAC,eAAe;gBACpB,IAAI,CAAC,eAAe,GAAG;YACzB;YAEA,QAAQ,GAAG,CAAC;QACd,EAAE,OAAO,OAAO;YACd,QAAQ,KAAK,CAAC,yBAAyB;QACzC;IACF;IAEA,sDAAsD;IACtD,aAAa,gBAAgB,MAAc,EAAiB;QAC1D,IAAI;YACF,MAAM,aAAa,IAAA,oMAAG,EAAC,qIAAE,EAAE,iBAAiB;YAC5C,MAAM,IAAA,uMAAM,EAAC,YAAY;gBACvB,UAAU;gBACV,cAAc,IAAA,gNAAe;gBAC7B,kBAAkB;YACpB,GAAG;gBAAE,OAAO;YAAK;YACjB,QAAQ,GAAG,CAAC;QACd,EAAE,OAAO,OAAO;YACd,QAAQ,KAAK,CAAC,iCAAiC;QACjD;IACF;AACF","debugId":null}},
    {"offset": {"line": 1051, "column": 0}, "map": {"version":3,"sources":["file:///home/eric/Loveworld-Singers-Rehearsal-Hub-Portal-Zonal-Mode/src/lib/error-handler.ts"],"sourcesContent":["// User-Friendly Error Handler\nexport class ErrorHandler {\n  // Convert Firebase auth errors to user-friendly messages\n  static getAuthErrorMessage(errorCode: string): string {\n    const errorMessages: { [key: string]: string } = {\n      // Authentication Errors\n      'auth/user-not-found': 'No account found with this email address. Please check your email or sign up.',\n      'auth/wrong-password': 'Incorrect password. Please try again or reset your password.',\n      'auth/invalid-email': 'Please enter a valid email address.',\n      'auth/user-disabled': 'This account has been disabled. Please contact support.',\n      'auth/too-many-requests': 'Too many failed attempts. Please try again later or reset your password.',\n      'auth/network-request-failed': 'Network error. Please check your internet connection and try again.',\n      \n      // Registration Errors\n      'auth/email-already-in-use': 'An account with this email already exists. Please sign in instead.',\n      'auth/weak-password': 'Password is too weak. Please use at least 6 characters with numbers and letters.',\n      'auth/invalid-password': 'Password must be at least 6 characters long.',\n      \n      // Session Errors\n      'auth/requires-recent-login': 'For security, please sign in again to continue.',\n      'auth/user-token-expired': 'Your session has expired. Please sign in again.',\n      'auth/invalid-user-token': 'Your session is invalid. Please sign in again.',\n      \n      // Google Sign-in Errors\n      'auth/popup-closed-by-user': 'Sign-in was cancelled. Please try again.',\n      'auth/popup-blocked': 'Pop-up was blocked by your browser. Please allow pop-ups and try again.',\n      'auth/cancelled-popup-request': 'Sign-in was cancelled. Please try again.',\n      \n      // General Errors\n      'auth/operation-not-allowed': 'This sign-in method is not enabled. Please contact support.',\n      'auth/invalid-api-key': 'Configuration error. Please contact support.',\n      'auth/app-deleted': 'App configuration error. Please contact support.',\n      'auth/invalid-credential': 'Invalid credentials. Please check your email and password.',\n      \n      // Custom Session Errors\n      'session/already-logged-in': 'This account is already logged in on another device. Please ask the account owner to log out from that device first, or sign up for your own account instead.',\n      'session/device-limit-reached': 'Maximum number of devices reached for this account.',\n      'session/invalid-device': 'This device is not authorized for this account.',\n      'device/already-registered': 'This device is already registered to another account. Please sign up for your own account instead.',\n    }\n    \n    return errorMessages[errorCode] || 'An unexpected error occurred. Please try again.'\n  }\n  \n  // Convert Firebase database errors to user-friendly messages\n  static getDatabaseErrorMessage(errorCode: string): string {\n    const errorMessages: { [key: string]: string } = {\n      'permission-denied': 'You don\\'t have permission to access this data.',\n      'not-found': 'The requested data was not found.',\n      'already-exists': 'This data already exists.',\n      'resource-exhausted': 'Service is temporarily unavailable. Please try again later.',\n      'failed-precondition': 'Operation failed. Please refresh and try again.',\n      'aborted': 'Operation was cancelled. Please try again.',\n      'out-of-range': 'Invalid data range provided.',\n      'unimplemented': 'This feature is not yet available.',\n      'internal': 'Internal server error. Please try again later.',\n      'unavailable': 'Service is temporarily unavailable. Please try again later.',\n      'data-loss': 'Data corruption detected. Please contact support.',\n      'unauthenticated': 'Please sign in to continue.',\n      'invalid-argument': 'Invalid data provided. Please check your input.',\n      'deadline-exceeded': 'Request timed out. Please try again.',\n      'cancelled': 'Operation was cancelled.',\n    }\n    \n    return errorMessages[errorCode] || 'A database error occurred. Please try again.'\n  }\n  \n  // Convert storage errors to user-friendly messages\n  static getStorageErrorMessage(errorCode: string): string {\n    const errorMessages: { [key: string]: string } = {\n      'storage/object-not-found': 'File not found.',\n      'storage/bucket-not-found': 'Storage service unavailable.',\n      'storage/project-not-found': 'Storage configuration error.',\n      'storage/quota-exceeded': 'Storage quota exceeded. Please contact support.',\n      'storage/unauthenticated': 'Please sign in to upload files.',\n      'storage/unauthorized': 'You don\\'t have permission to upload files.',\n      'storage/retry-limit-exceeded': 'Upload failed after multiple attempts. Please try again.',\n      'storage/invalid-checksum': 'File upload corrupted. Please try again.',\n      'storage/canceled': 'Upload was cancelled.',\n      'storage/invalid-event-name': 'Upload configuration error.',\n      'storage/invalid-url': 'Invalid file URL.',\n      'storage/invalid-argument': 'Invalid file data.',\n      'storage/no-default-bucket': 'Storage service not configured.',\n      'storage/cannot-slice-blob': 'File processing error. Please try a different file.',\n      'storage/server-file-wrong-size': 'File size mismatch. Please try again.',\n    }\n    \n    return errorMessages[errorCode] || 'File upload error. Please try again.'\n  }\n  \n  // Extract error code from Firebase error\n  static extractErrorCode(error: any): string {\n    if (typeof error === 'string') {\n      return error\n    }\n    \n    if (error?.code) {\n      return error.code\n    }\n    \n    if (error?.message) {\n      // Try to extract code from message\n      const codeMatch = error.message.match(/\\(([^)]+)\\)/)\n      if (codeMatch) {\n        return codeMatch[1]\n      }\n    }\n    \n    return 'unknown-error'\n  }\n  \n  // Get user-friendly error message for any Firebase error\n  static getErrorMessage(error: any, context: 'auth' | 'database' | 'storage' = 'auth'): string {\n    const errorCode = this.extractErrorCode(error)\n    \n    switch (context) {\n      case 'auth':\n        return this.getAuthErrorMessage(errorCode)\n      case 'database':\n        return this.getDatabaseErrorMessage(errorCode)\n      case 'storage':\n        return this.getStorageErrorMessage(errorCode)\n      default:\n        return this.getAuthErrorMessage(errorCode)\n    }\n  }\n  \n  // Show user-friendly error toast/alert\n  static showError(error: any, context: 'auth' | 'database' | 'storage' = 'auth'): void {\n    const message = this.getErrorMessage(error, context)\n    \n    // You can replace this with your preferred notification system\n    // For now, using alert, but you can integrate with toast libraries\n    alert(message)\n    \n    // Log the actual error for debugging (only in development)\n    if (process.env.NODE_ENV === 'development') {\n      console.error('Detailed error:', error)\n    }\n  }\n  \n  // Validate common inputs and return user-friendly messages\n  static validateEmail(email: string): string | null {\n    if (!email) return 'Email is required'\n    if (!/^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$/.test(email)) return 'Please enter a valid email address'\n    return null\n  }\n  \n  static validatePassword(password: string): string | null {\n    if (!password) return 'Password is required'\n    if (password.length < 6) return 'Password must be at least 6 characters long'\n    return null\n  }\n  \n  static validateName(name: string): string | null {\n    if (!name) return 'Name is required'\n    if (name.length < 2) return 'Name must be at least 2 characters long'\n    if (!/^[a-zA-Z\\s]+$/.test(name)) return 'Name can only contain letters and spaces'\n    return null\n  }\n}"],"names":[],"mappings":"AAAA,8BAA8B;;;;;AACvB,MAAM;IACX,yDAAyD;IACzD,OAAO,oBAAoB,SAAiB,EAAU;QACpD,MAAM,gBAA2C;YAC/C,wBAAwB;YACxB,uBAAuB;YACvB,uBAAuB;YACvB,sBAAsB;YACtB,sBAAsB;YACtB,0BAA0B;YAC1B,+BAA+B;YAE/B,sBAAsB;YACtB,6BAA6B;YAC7B,sBAAsB;YACtB,yBAAyB;YAEzB,iBAAiB;YACjB,8BAA8B;YAC9B,2BAA2B;YAC3B,2BAA2B;YAE3B,wBAAwB;YACxB,6BAA6B;YAC7B,sBAAsB;YACtB,gCAAgC;YAEhC,iBAAiB;YACjB,8BAA8B;YAC9B,wBAAwB;YACxB,oBAAoB;YACpB,2BAA2B;YAE3B,wBAAwB;YACxB,6BAA6B;YAC7B,gCAAgC;YAChC,0BAA0B;YAC1B,6BAA6B;QAC/B;QAEA,OAAO,aAAa,CAAC,UAAU,IAAI;IACrC;IAEA,6DAA6D;IAC7D,OAAO,wBAAwB,SAAiB,EAAU;QACxD,MAAM,gBAA2C;YAC/C,qBAAqB;YACrB,aAAa;YACb,kBAAkB;YAClB,sBAAsB;YACtB,uBAAuB;YACvB,WAAW;YACX,gBAAgB;YAChB,iBAAiB;YACjB,YAAY;YACZ,eAAe;YACf,aAAa;YACb,mBAAmB;YACnB,oBAAoB;YACpB,qBAAqB;YACrB,aAAa;QACf;QAEA,OAAO,aAAa,CAAC,UAAU,IAAI;IACrC;IAEA,mDAAmD;IACnD,OAAO,uBAAuB,SAAiB,EAAU;QACvD,MAAM,gBAA2C;YAC/C,4BAA4B;YAC5B,4BAA4B;YAC5B,6BAA6B;YAC7B,0BAA0B;YAC1B,2BAA2B;YAC3B,wBAAwB;YACxB,gCAAgC;YAChC,4BAA4B;YAC5B,oBAAoB;YACpB,8BAA8B;YAC9B,uBAAuB;YACvB,4BAA4B;YAC5B,6BAA6B;YAC7B,6BAA6B;YAC7B,kCAAkC;QACpC;QAEA,OAAO,aAAa,CAAC,UAAU,IAAI;IACrC;IAEA,yCAAyC;IACzC,OAAO,iBAAiB,KAAU,EAAU;QAC1C,IAAI,OAAO,UAAU,UAAU;YAC7B,OAAO;QACT;QAEA,IAAI,OAAO,MAAM;YACf,OAAO,MAAM,IAAI;QACnB;QAEA,IAAI,OAAO,SAAS;YAClB,mCAAmC;YACnC,MAAM,YAAY,MAAM,OAAO,CAAC,KAAK,CAAC;YACtC,IAAI,WAAW;gBACb,OAAO,SAAS,CAAC,EAAE;YACrB;QACF;QAEA,OAAO;IACT;IAEA,yDAAyD;IACzD,OAAO,gBAAgB,KAAU,EAAE,UAA2C,MAAM,EAAU;QAC5F,MAAM,YAAY,IAAI,CAAC,gBAAgB,CAAC;QAExC,OAAQ;YACN,KAAK;gBACH,OAAO,IAAI,CAAC,mBAAmB,CAAC;YAClC,KAAK;gBACH,OAAO,IAAI,CAAC,uBAAuB,CAAC;YACtC,KAAK;gBACH,OAAO,IAAI,CAAC,sBAAsB,CAAC;YACrC;gBACE,OAAO,IAAI,CAAC,mBAAmB,CAAC;QACpC;IACF;IAEA,uCAAuC;IACvC,OAAO,UAAU,KAAU,EAAE,UAA2C,MAAM,EAAQ;QACpF,MAAM,UAAU,IAAI,CAAC,eAAe,CAAC,OAAO;QAE5C,+DAA+D;QAC/D,mEAAmE;QACnE,MAAM;QAEN,2DAA2D;QAC3D,wCAA4C;YAC1C,QAAQ,KAAK,CAAC,mBAAmB;QACnC;IACF;IAEA,2DAA2D;IAC3D,OAAO,cAAc,KAAa,EAAiB;QACjD,IAAI,CAAC,OAAO,OAAO;QACnB,IAAI,CAAC,6BAA6B,IAAI,CAAC,QAAQ,OAAO;QACtD,OAAO;IACT;IAEA,OAAO,iBAAiB,QAAgB,EAAiB;QACvD,IAAI,CAAC,UAAU,OAAO;QACtB,IAAI,SAAS,MAAM,GAAG,GAAG,OAAO;QAChC,OAAO;IACT;IAEA,OAAO,aAAa,IAAY,EAAiB;QAC/C,IAAI,CAAC,MAAM,OAAO;QAClB,IAAI,KAAK,MAAM,GAAG,GAAG,OAAO;QAC5B,IAAI,CAAC,gBAAgB,IAAI,CAAC,OAAO,OAAO;QACxC,OAAO;IACT;AACF","debugId":null}},
    {"offset": {"line": 1198, "column": 0}, "map": {"version":3,"sources":["file:///home/eric/Loveworld-Singers-Rehearsal-Hub-Portal-Zonal-Mode/src/lib/firebase-auth.ts"],"sourcesContent":["import { \n  signInWithEmailAndPassword, createUserWithEmailAndPassword, signOut,\n  onAuthStateChanged, User, signInWithPopup, GoogleAuthProvider,\n  deleteUser, setPersistence, browserLocalPersistence\n} from 'firebase/auth'\nimport { doc, getDoc, setDoc } from 'firebase/firestore'\n\nimport { auth, db } from './firebase-setup'\nimport { SessionManager } from './session-manager'\nimport { ErrorHandler } from './error-handler'\n\nexport class FirebaseAuthService {\n  static async signIn(email: string, password: string, rememberMe: boolean = true) {\n    try {\n      const emailError = ErrorHandler.validateEmail(email)\n      if (emailError) {\n        return { user: null, error: emailError, userFriendly: true }\n      }\n      \n      const passwordError = ErrorHandler.validatePassword(password)\n      if (passwordError) {\n        return { user: null, error: passwordError, userFriendly: true }\n      }\n      \n      await setPersistence(auth, browserLocalPersistence)\n      const result = await signInWithEmailAndPassword(auth, email, password)\n      \n      const sessionCheck = await SessionManager.canUserLogin(result.user.uid)\n      if (!sessionCheck.canLogin) {\n        await signOut(auth)\n        return { \n          user: null, \n          error: `This account is already logged in on ${sessionCheck.activeDevice}. Please ask the account owner to log out from that device first, or sign up for your own account instead.`,\n          userFriendly: true \n        }\n      }\n      \n      await SessionManager.createSession(result.user)\n      \n      if (rememberMe && typeof window !== 'undefined') {\n        const token = await result.user.getIdToken()\n        localStorage.setItem('authToken', token)\n        localStorage.setItem('userEmail', email)\n        localStorage.setItem('userId', result.user.uid)\n        localStorage.setItem('lastLoginTime', Date.now().toString())\n      }\n      \n      return { user: result.user, error: null }\n    } catch (error: any) {\n      const friendlyError = ErrorHandler.getErrorMessage(error, 'auth')\n      return { user: null, error: friendlyError, userFriendly: true }\n    }\n  }\n  \n  static async signUp(email: string, password: string, userData: any) {\n    try {\n      await setPersistence(auth, browserLocalPersistence)\n      const result = await createUserWithEmailAndPassword(auth, email, password)\n      \n      await setDoc(doc(db, 'profiles', result.user.uid), {\n        ...userData,\n        createdAt: new Date(),\n        updatedAt: new Date()\n      })\n      \n      return { user: result.user, error: null }\n    } catch (error: any) {\n      return { user: null, error: error.message }\n    }\n  }\n\n  static async signOut() {\n    try {\n      const currentUser = auth.currentUser\n      if (currentUser) {\n        await SessionManager.endSession(currentUser.uid)\n      }\n      await signOut(auth)\n      return { error: null, success: true }\n    } catch (error: any) {\n      const friendlyError = ErrorHandler.getErrorMessage(error, 'auth')\n      return { error: friendlyError, success: false }\n    }\n  }\n\n  static getCurrentUser(): User | null {\n    return auth.currentUser\n  }\n\n  static onAuthStateChange(callback: (user: User | null) => void) {\n    return onAuthStateChanged(auth, callback)\n  }\n\n  static async ensurePersistence() {\n    try {\n      await setPersistence(auth, browserLocalPersistence)\n      return new Promise((resolve) => {\n        const unsubscribe = onAuthStateChanged(auth, (user) => {\n          unsubscribe()\n          resolve(user)\n        })\n      })\n    } catch (error) {\n      console.error('Failed to set auth persistence:', error)\n    }\n  }\n\n  static async checkPersistenceStatus() {\n    try {\n      const currentUser = auth.currentUser\n      return {\n        hasUser: !!currentUser,\n        userEmail: currentUser?.email || null,\n        persistenceSet: true,\n        message: currentUser ? 'User will stay signed in' : 'No user signed in'\n      }\n    } catch (error) {\n      return {\n        hasUser: false,\n        userEmail: null,\n        persistenceSet: false,\n        message: 'Error checking persistence'\n      }\n    }\n  }\n\n  static async getUserProfile(userId: string) {\n    try {\n      const docRef = doc(db, 'profiles', userId)\n      const docSnap = await getDoc(docRef)\n      return docSnap.exists() ? docSnap.data() : null\n    } catch (error) {\n      console.error('Error getting user profile:', error)\n      return null\n    }\n  }\n\n  static async testConnection() {\n    try {\n      if (!auth) {\n        return { status: 'error', message: 'Firebase Auth not initialized' }\n      }\n      const currentUser = auth.currentUser\n      return { \n        status: 'success', \n        message: 'Firebase Auth connected successfully',\n        currentUser: currentUser ? 'User logged in' : 'No user logged in'\n      }\n    } catch (error: any) {\n      return { status: 'error', message: error.message }\n    }\n  }\n\n  static async createUserWithEmailAndPassword(email: string, password: string, userData?: any) {\n    try {\n      await setPersistence(auth, browserLocalPersistence)\n      const result = await createUserWithEmailAndPassword(auth, email, password)\n\n      try {\n        if (userData && Object.keys(userData).length > 0) {\n          const profileData = {\n            id: result.user.uid,\n            email: result.user.email,\n            profile_completed: true,\n            created_at: new Date().toISOString(),\n            updated_at: new Date().toISOString(),\n            ...userData\n          }\n          await setDoc(doc(db, 'profiles', result.user.uid), profileData)\n        }\n        return { user: result.user, error: null }\n      } catch (profileError: any) {\n        try {\n          console.error('Failed to create profile, deleting auth user:', profileError)\n          await deleteUser(result.user)\n        } catch (cleanupError) {\n          console.error('Failed to delete auth user after profile error:', cleanupError)\n        }\n        return { user: null, error: profileError?.message || 'Failed to complete signup. Please check your connection and try again.' }\n      }\n    } catch (error: any) {\n      return { user: null, error: error.message }\n    }\n  }\n\n  static async signInWithEmailAndPassword(email: string, password: string, rememberMe: boolean = true) {\n    return this.signIn(email, password, rememberMe)\n  }\n\n  static async autoLogin(): Promise<{ user: User | null, error: string | null }> {\n    try {\n      if (typeof window === 'undefined') {\n        return { user: null, error: 'Not in browser' }\n      }\n\n      const isLoggingOut = localStorage.getItem('isLoggingOut') === 'true' || \n                          localStorage.getItem('logging_out') === 'true'\n      const urlParams = new URLSearchParams(window.location.search)\n      const logoutFromUrl = urlParams.get('logout') === 'true'\n      \n      if (isLoggingOut || logoutFromUrl) {\n        return { user: null, error: 'Logout in progress' }\n      }\n\n      const authToken = localStorage.getItem('authToken')\n      const userId = localStorage.getItem('userId')\n      const lastLoginTime = localStorage.getItem('lastLoginTime')\n\n      if (!authToken || !userId || !lastLoginTime) {\n        return { user: null, error: 'No stored credentials' }\n      }\n\n      const tokenAge = Date.now() - parseInt(lastLoginTime)\n      const maxAge = 7 * 24 * 60 * 60 * 1000 // 7 days\n      if (tokenAge > maxAge) {\n        localStorage.removeItem('authToken')\n        localStorage.removeItem('userId')\n        localStorage.removeItem('userEmail')\n        localStorage.removeItem('lastLoginTime')\n        return { user: null, error: 'Token expired' }\n      }\n\n      const currentUser = auth.currentUser\n      if (currentUser && currentUser.uid === userId) {\n        return { user: currentUser, error: null }\n      }\n\n      return { user: null, error: 'Session expired - please login again' }\n    } catch (error: any) {\n      console.error('Auto-login failed:', error)\n      return { user: null, error: error.message }\n    }\n  }\n\n  static async resetPassword(email: string) {\n    try {\n      const { sendPasswordResetEmail } = await import('firebase/auth')\n      const actionCodeSettings = (typeof window !== 'undefined') ? {\n        url: `${window.location.origin}/auth/reset-password`,\n        handleCodeInApp: true\n      } : undefined as any\n\n      await sendPasswordResetEmail(auth, email, actionCodeSettings)\n      return { error: null }\n    } catch (error: any) {\n      return { error: error.message }\n    }\n  }\n\n  static async verifyPasswordResetCode(oobCode: string) {\n    try {\n      const { verifyPasswordResetCode } = await import('firebase/auth')\n      const email = await verifyPasswordResetCode(auth, oobCode)\n      return { email, error: null }\n    } catch (error: any) {\n      return { email: null, error: error.message }\n    }\n  }\n\n  static async confirmPasswordReset(oobCode: string, newPassword: string) {\n    try {\n      const { confirmPasswordReset } = await import('firebase/auth')\n      await confirmPasswordReset(auth, oobCode, newPassword)\n      return { error: null }\n    } catch (error: any) {\n      return { error: error.message }\n    }\n  }\n\n  static async updatePassword(newPassword: string) {\n    try {\n      const { updatePassword } = await import('firebase/auth')\n      const user = auth.currentUser\n      if (!user) throw new Error('No user logged in')\n      await updatePassword(user, newPassword)\n      return { error: null }\n    } catch (error: any) {\n      return { error: error.message }\n    }\n  }\n\n  static async signInWithGoogle() {\n    try {\n      await setPersistence(auth, browserLocalPersistence)\n      const provider = new GoogleAuthProvider()\n      const result = await signInWithPopup(auth, provider)\n      \n      const userProfile = await this.getUserProfile(result.user.uid)\n      if (!userProfile) {\n        const displayName = result.user.displayName || ''\n        const nameParts = displayName.split(' ')\n        await setDoc(doc(db, 'profiles', result.user.uid), {\n          id: result.user.uid,\n          first_name: nameParts[0] || '',\n          last_name: nameParts.slice(1).join(' ') || '',\n          email: result.user.email,\n          profile_completed: false,\n          created_at: new Date().toISOString(),\n          updated_at: new Date().toISOString()\n        })\n      }\n      \n      return { user: result.user, error: null }\n    } catch (error: any) {\n      return { user: null, error: error.message }\n    }\n  }\n\n  static async deleteUser() {\n    try {\n      const user = auth.currentUser\n      if (!user) throw new Error('No user logged in')\n      await deleteUser(user)\n      return { success: true, error: null }\n    } catch (error: any) {\n      return { success: false, error: error.message }\n    }\n  }\n}\n"],"names":[],"mappings":";;;;AAAA;AAAA;AAKA;AAAA;AAEA;AACA;AACA;;;;;;AAEO,MAAM;IACX,aAAa,OAAO,KAAa,EAAE,QAAgB,EAAE,aAAsB,IAAI,EAAE;QAC/E,IAAI;YACF,MAAM,aAAa,8IAAY,CAAC,aAAa,CAAC;YAC9C,IAAI,YAAY;gBACd,OAAO;oBAAE,MAAM;oBAAM,OAAO;oBAAY,cAAc;gBAAK;YAC7D;YAEA,MAAM,gBAAgB,8IAAY,CAAC,gBAAgB,CAAC;YACpD,IAAI,eAAe;gBACjB,OAAO;oBAAE,MAAM;oBAAM,OAAO;oBAAe,cAAc;gBAAK;YAChE;YAEA,MAAM,IAAA,oLAAc,EAAC,uIAAI,EAAE,6LAAuB;YAClD,MAAM,SAAS,MAAM,IAAA,gMAA0B,EAAC,uIAAI,EAAE,OAAO;YAE7D,MAAM,eAAe,MAAM,kJAAc,CAAC,YAAY,CAAC,OAAO,IAAI,CAAC,GAAG;YACtE,IAAI,CAAC,aAAa,QAAQ,EAAE;gBAC1B,MAAM,IAAA,6KAAO,EAAC,uIAAI;gBAClB,OAAO;oBACL,MAAM;oBACN,OAAO,CAAC,qCAAqC,EAAE,aAAa,YAAY,CAAC,0GAA0G,CAAC;oBACpL,cAAc;gBAChB;YACF;YAEA,MAAM,kJAAc,CAAC,aAAa,CAAC,OAAO,IAAI;YAE9C;;YAQA,OAAO;gBAAE,MAAM,OAAO,IAAI;gBAAE,OAA