e,MAAM;YAC3B,OAAO;gBAAE,OAAO;YAAK;QACvB,EAAE,OAAO,OAAY;YACnB,OAAO;gBAAE,OAAO,MAAM,OAAO;YAAC;QAChC;IACF;IAEA,aAAa,mBAAmB;QAC9B,IAAI;YACF,MAAM,IAAA,oLAAc,EAAC,uIAAI,EAAE,6LAAuB;YAClD,MAAM,WAAW,IAAI,wLAAkB;YACvC,MAAM,SAAS,MAAM,IAAA,qLAAe,EAAC,uIAAI,EAAE;YAE3C,MAAM,cAAc,MAAM,IAAI,CAAC,cAAc,CAAC,OAAO,IAAI,CAAC,GAAG;YAC7D,IAAI,CAAC,aAAa;gBAChB,MAAM,cAAc,OAAO,IAAI,CAAC,WAAW,IAAI;gBAC/C,MAAM,YAAY,YAAY,KAAK,CAAC;gBACpC,MAAM,IAAA,uMAAM,EAAC,IAAA,oMAAG,EAAC,qIAAE,EAAE,YAAY,OAAO,IAAI,CAAC,GAAG,GAAG;oBACjD,IAAI,OAAO,IAAI,CAAC,GAAG;oBACnB,YAAY,SAAS,CAAC,EAAE,IAAI;oBAC5B,WAAW,UAAU,KAAK,CAAC,GAAG,IAAI,CAAC,QAAQ;oBAC3C,OAAO,OAAO,IAAI,CAAC,KAAK;oBACxB,mBAAmB;oBACnB,YAAY,IAAI,OAAO,WAAW;oBAClC,YAAY,IAAI,OAAO,WAAW;gBACpC;YACF;YAEA,OAAO;gBAAE,MAAM,OAAO,IAAI;gBAAE,OAAO;YAAK;QAC1C,EAAE,OAAO,OAAY;YACnB,OAAO;gBAAE,MAAM;gBAAM,OAAO,MAAM,OAAO;YAAC;QAC5C;IACF;IAEA,aAAa,aAAa;QACxB,IAAI;YACF,MAAM,OAAO,uIAAI,CAAC,WAAW;YAC7B,IAAI,CAAC,MAAM,MAAM,IAAI,MAAM;YAC3B,MAAM,IAAA,gLAAU,EAAC;YACjB,OAAO;gBAAE,SAAS;gBAAM,OAAO;YAAK;QACtC,EAAE,OAAO,OAAY;YACnB,OAAO;gBAAE,SAAS;gBAAO,OAAO,MAAM,OAAO;YAAC;QAChD;IACF;AACF","debugId":null}},
    {"offset": {"line": 1544, "column": 0}, "map": {"version":3,"sources":["file:///home/eric/Loveworld-Singers-Rehearsal-Hub-Portal-Zonal-Mode/src/utils/low-data-optimizer.ts"],"sourcesContent":["// Low Data Optimizer - Super fast loading with minimal Firebase costs\n// Instagram-style optimization for poor connections\n\ninterface ConnectionInfo {\n  effectiveType: string;\n  downlink: number;\n  rtt: number;\n  saveData: boolean;\n}\n\nclass LowDataOptimizer {\n  private static instance: LowDataOptimizer;\n  private connectionInfo: ConnectionInfo | null = null;\n  private isLowData = false;\n  private cache = new Map<string, { data: any; timestamp: number; ttl: number }>();\n  \n  // Cache TTLs based on connection speed\n  private readonly TTL = {\n    FAST: 5 * 60 * 1000,      // 5 minutes for fast connections\n    SLOW: 30 * 60 * 1000,     // 30 minutes for slow connections\n    VERY_SLOW: 2 * 60 * 60 * 1000, // 2 hours for very slow connections\n    OFFLINE: 24 * 60 * 60 * 1000   // 24 hours when offline\n  };\n\n  static getInstance(): LowDataOptimizer {\n    if (!LowDataOptimizer.instance) {\n      LowDataOptimizer.instance = new LowDataOptimizer();\n    }\n    return LowDataOptimizer.instance;\n  }\n\n  init() {\n    this.detectConnection();\n    this.setupEventListeners();\n    console.log('📱 Low Data Optimizer initialized');\n  }\n\n  private detectConnection() {\n    if ('connection' in navigator) {\n      const connection = (navigator as any).connection;\n      this.connectionInfo = {\n        effectiveType: connection.effectiveType || 'unknown',\n        downlink: connection.downlink || 0,\n        rtt: connection.rtt || 0,\n        saveData: connection.saveData || false\n      };\n\n      // Determine if this is a low data connection\n      this.isLowData = \n        this.connectionInfo.effectiveType === 'slow-2g' ||\n        this.connectionInfo.effectiveType === '2g' ||\n        this.connectionInfo.downlink < 1 ||\n        this.connectionInfo.saveData;\n\n      console.log('📊 Connection detected:', {\n        type: this.connectionInfo.effectiveType,\n        speed: this.connectionInfo.downlink + 'Mbps',\n        rtt: this.connectionInfo.rtt + 'ms',\n        saveData: this.connectionInfo.saveData,\n        isLowData: this.isLowData\n      });\n\n      if (this.isLowData) {\n        console.log('⚠️ Low data connection detected - enabling aggressive caching');\n      }\n    }\n  }\n\n  private setupEventListeners() {\n    if ('connection' in navigator) {\n      const connection = (navigator as any).connection;\n      connection.addEventListener('change', () => {\n        this.detectConnection();\n      });\n    }\n\n    // Listen for online/offline events\n    window.addEventListener('online', () => {\n      console.log('🌐 Connection restored');\n      this.detectConnection();\n    });\n\n    window.addEventListener('offline', () => {\n      console.log('📴 Connection lost');\n      this.isLowData = true;\n    });\n  }\n\n  // Get cache TTL based on connection speed\n  getCacheTTL(): number {\n    if (!navigator.onLine) return this.TTL.OFFLINE;\n    if (!this.connectionInfo) return this.TTL.FAST;\n    \n    switch (this.connectionInfo.effectiveType) {\n      case 'slow-2g':\n      case '2g':\n        return this.TTL.VERY_SLOW;\n      case '3g':\n        return this.TTL.SLOW;\n      default:\n        return this.TTL.FAST;\n    }\n  }\n\n  // Smart caching with connection-aware TTL\n  set(key: string, data: any): void {\n    const ttl = this.getCacheTTL();\n    this.cache.set(key, {\n      data,\n      timestamp: Date.now(),\n      ttl\n    });\n\n    // Also store in localStorage for persistence\n    try {\n      localStorage.setItem(`lowdata_${key}`, JSON.stringify({\n        data,\n        timestamp: Date.now(),\n        ttl\n      }));\n    } catch (error) {\n      console.warn('Failed to store in localStorage:', error);\n    }\n\n    console.log(`💾 Cached ${key} for ${ttl/1000/60} minutes (low data mode)`);\n  }\n\n  get(key: string): any | null {\n    // Check memory cache first\n    const cached = this.cache.get(key);\n    if (cached && Date.now() - cached.timestamp < cached.ttl) {\n      console.log(`⚡ Cache hit: ${key} (instant load)`);\n      return cached.data;\n    }\n\n    // Check localStorage\n    try {\n      const stored = localStorage.getItem(`lowdata_${key}`);\n      if (stored) {\n        const parsed = JSON.parse(stored);\n        if (Date.now() - parsed.timestamp < parsed.ttl) {\n          // Restore to memory cache\n          this.cache.set(key, parsed);\n          console.log(`💾 Restored ${key} from localStorage`);\n          return parsed.data;\n        } else {\n          // Expired, remove it\n          localStorage.removeItem(`lowdata_${key}`);\n        }\n      }\n    } catch (error) {\n      console.warn('Failed to read from localStorage:', error);\n    }\n\n    return null;\n  }\n\n  // Check if we should make a Firebase request\n  shouldFetch(key: string): boolean {\n    const cached = this.get(key);\n    if (cached) {\n      console.log(`🚫 Skipping Firebase request for ${key} (cached)`);\n      return false;\n    }\n    \n    console.log(`🔥 Making Firebase request for ${key}`);\n    return true;\n  }\n\n  // Get connection info\n  getConnectionInfo(): ConnectionInfo | null {\n    return this.connectionInfo;\n  }\n\n  // Check if low data mode\n  isLowDataMode(): boolean {\n    return this.isLowData;\n  }\n\n  // Clear cache\n  clearCache(): void {\n    this.cache.clear();\n    // Clear localStorage cache\n    Object.keys(localStorage).forEach(key => {\n      if (key.startsWith('lowdata_')) {\n        localStorage.removeItem(key);\n      }\n    });\n    console.log('🧹 Low data cache cleared');\n  }\n\n  // Get cache stats\n  getCacheStats(): { size: number; keys: string[] } {\n    return {\n      size: this.cache.size,\n      keys: Array.from(this.cache.keys())\n    };\n  }\n}\n\nexport const lowDataOptimizer = LowDataOptimizer.getInstance();\n\n\n"],"names":[],"mappings":"AAAA,sEAAsE;AACtE,oDAAoD;;;;;AASpD,MAAM;IACJ,OAAe,SAA2B;IAClC,iBAAwC,KAAK;IAC7C,YAAY,MAAM;IAClB,QAAQ,IAAI,MAA6D;IAEjF,uCAAuC;IACtB,MAAM;QACrB,MAAM,IAAI,KAAK;QACf,MAAM,KAAK,KAAK;QAChB,WAAW,IAAI,KAAK,KAAK;QACzB,SAAS,KAAK,KAAK,KAAK,KAAO,wBAAwB;IACzD,EAAE;IAEF,OAAO,cAAgC;QACrC,IAAI,CAAC,iBAAiB,QAAQ,EAAE;YAC9B,iBAAiB,QAAQ,GAAG,IAAI;QAClC;QACA,OAAO,iBAAiB,QAAQ;IAClC;IAEA,OAAO;QACL,IAAI,CAAC,gBAAgB;QACrB,IAAI,CAAC,mBAAmB;QACxB,QAAQ,GAAG,CAAC;IACd;IAEQ,mBAAmB;QACzB,IAAI,gBAAgB,WAAW;YAC7B,MAAM,aAAa,AAAC,UAAkB,UAAU;YAChD,IAAI,CAAC,cAAc,GAAG;gBACpB,eAAe,WAAW,aAAa,IAAI;gBAC3C,UAAU,WAAW,QAAQ,IAAI;gBACjC,KAAK,WAAW,GAAG,IAAI;gBACvB,UAAU,WAAW,QAAQ,IAAI;YACnC;YAEA,6CAA6C;YAC7C,IAAI,CAAC,SAAS,GACZ,IAAI,CAAC,cAAc,CAAC,aAAa,KAAK,aACtC,IAAI,CAAC,cAAc,CAAC,aAAa,KAAK,QACtC,IAAI,CAAC,cAAc,CAAC,QAAQ,GAAG,KAC/B,IAAI,CAAC,cAAc,CAAC,QAAQ;YAE9B,QAAQ,GAAG,CAAC,2BAA2B;gBACrC,MAAM,IAAI,CAAC,cAAc,CAAC,aAAa;gBACvC,OAAO,IAAI,CAAC,cAAc,CAAC,QAAQ,GAAG;gBACtC,KAAK,IAAI,CAAC,cAAc,CAAC,GAAG,GAAG;gBAC/B,UAAU,IAAI,CAAC,cAAc,CAAC,QAAQ;gBACtC,WAAW,IAAI,CAAC,SAAS;YAC3B;YAEA,IAAI,IAAI,CAAC,SAAS,EAAE;gBAClB,QAAQ,GAAG,CAAC;YACd;QACF;IACF;IAEQ,sBAAsB;QAC5B,IAAI,gBAAgB,WAAW;YAC7B,MAAM,aAAa,AAAC,UAAkB,UAAU;YAChD,WAAW,gBAAgB,CAAC,UAAU;gBACpC,IAAI,CAAC,gBAAgB;YACvB;QACF;QAEA,mCAAmC;QACnC,OAAO,gBAAgB,CAAC,UAAU;YAChC,QAAQ,GAAG,CAAC;YACZ,IAAI,CAAC,gBAAgB;QACvB;QAEA,OAAO,gBAAgB,CAAC,WAAW;YACjC,QAAQ,GAAG,CAAC;YACZ,IAAI,CAAC,SAAS,GAAG;QACnB;IACF;IAEA,0CAA0C;IAC1C,cAAsB;QACpB,IAAI,CAAC,UAAU,MAAM,EAAE,OAAO,IAAI,CAAC,GAAG,CAAC,OAAO;QAC9C,IAAI,CAAC,IAAI,CAAC,cAAc,EAAE,OAAO,IAAI,CAAC,GAAG,CAAC,IAAI;QAE9C,OAAQ,IAAI,CAAC,cAAc,CAAC,aAAa;YACvC,KAAK;YACL,KAAK;gBACH,OAAO,IAAI,CAAC,GAAG,CAAC,SAAS;YAC3B,KAAK;gBACH,OAAO,IAAI,CAAC,GAAG,CAAC,IAAI;YACtB;gBACE,OAAO,IAAI,CAAC,GAAG,CAAC,IAAI;QACxB;IACF;IAEA,0CAA0C;IAC1C,IAAI,GAAW,EAAE,IAAS,EAAQ;QAChC,MAAM,MAAM,IAAI,CAAC,WAAW;QAC5B,IAAI,CAAC,KAAK,CAAC,GAAG,CAAC,KAAK;YAClB;YACA,WAAW,KAAK,GAAG;YACnB;QACF;QAEA,6CAA6C;QAC7C,IAAI;YACF,aAAa,OAAO,CAAC,CAAC,QAAQ,EAAE,KAAK,EA